type Verse = { n: number; text: string; };

export const LEVITICUS_CHAPTERS: Record<number, Verse[]> = {
  1: [
    { n: 1, text: 'Yehovha a vitana Moxe, a vulavula na yena kusukela etabernakela ya nhlanganiso, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko un’wana exikarhi ka n’wina a tisa munyikelo eka Yehovha, mi ta tisa munyikelo wa n’wina hi swifuwo, hi tihomu ni hi tinyimpfu.”' },
    { n: 3, text: '“Loko munyikelo wa yena wu ri xitlhavelo xo hisiwa xa tihomu, a a tise xinuna lexi nga riki na xilaveko; a a xi tise emunyangweni wa tabernakela ya nhlanganiso, leswaku xi amukeleka mahlweni ka Yehovha.”' },
    { n: 4, text: '“A a be voko ra yena ehenhla ka nhloko ya xitlhavelo xo hisiwa, xi ta amukeleka tanihi mukutsulo wa yena.”' },
    { n: 5, text: '“A a tlhave xihomu mahlweni ka Yehovha; vana va Aroni, vaprista, va ta tisa ngati, va chela ngati ealitari ku rhendzela, leyi nga emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 6, text: '“A a hlubhe xitlhavelo xo hisiwa, a xi tsema hi swiphemu.”' },
    { n: 7, text: '“Vana va Aroni, muprista, va ta veka ndzilo ealitari, va hlela tihunyi ehenhla ka ndzilo.”' },
    { n: 8, text: '“Vaprista va ta hlela swiphemu, ni nhloko, ni mafurha, ehenhla ka tihunyi leti nga ealitari.”' },
    { n: 9, text: '“A a hlantswa marumbu ya xona ni milenge ya xona hi mati; muprista a a hise hinkwaswo ealitari, i xitlhavelo xo hisiwa, munyikelo wa ndzilo, nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 10, text: '“Loko munyikelo wa yena wu ri wa tinyimpfu kumbe wa timbuti, a a tise xinuna lexi nga riki na xilaveko.”' },
    { n: 11, text: '“A a xi tlhavela etlhelweni ra n’walungu ra alitari mahlweni ka Yehovha; vana va Aroni, vaprista, va ta chela ngati ya xona ealitari ku rhendzela.”' },
    { n: 12, text: '“A a xi tsema hi swiphemu, ni nhloko ya xona, ni mafurha ya xona, muprista a a swi hlela ehenhla ka tihunyi leti nga ealitari.”' },
    { n: 13, text: '“A a hlantswa marumbu ya xona ni milenge ya xona hi mati; muprista a a swi nyikela hinkwaswo, a swi hisa ealitari, i xitlhavelo xo hisiwa, munyikelo wa ndzilo, nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 14, text: '“Loko munyikelo wa yena eka Yehovha wu ri wa tinyenyana, a a tise munyikelo wa yena hi tinjiwa kumbe hi swiwa-tiva.”' },
    { n: 15, text: '“Muprista a a xi tise ealitari, a hlayi nhloko ya xona, a xi hisa ealitari; ngati ya xona yi ta kamyuriwa etlhelweni ra alitari.”' },
    { n: 16, text: '“A a susa xigadzi xa xona ni swa le ndzeni, a swi cukumeta etlhelweni ra alitari, laha ku nga ni nkuma.”' },
    { n: 17, text: '“A a xi handza hi tiphiko ta xona, kambe a nga xi hambanisi; muprista a a xi hisa ealitari, ehenhla ka tihunyi leti nga ealitari; i xitlhavelo xo hisiwa, munyikelo wa ndzilo, nun’hwelo lowu tsakisaka Yehovha.”' }
  ],
  2: [
    { n: 1, text: '“Loko munhu a tisa munyikelo wa xinkwa eka Yehovha, munyikelo wa yena wu ta va wa mapa lamamanene; a a wu chele mafurha, a wu vekelela nun’hwelo wa swirungo.”' },
    { n: 2, text: '“A a wu tise eka vana va Aroni, vaprista; a a teke ndzalo wa voko ra yena hi mapa ya wona, ni mafurha ya wona, ni nun’hwelo hinkwawo wa swirungo; muprista a a wu hise hi mitsumbula ealitari, i munyikelo lowu nun’hwelo wa wona wu tsakisaka Yehovha.”' },
    { n: 3, text: '“Leswi swi salaka eka munyikelo wa xinkwa swi ta va swa Aroni ni vana va yena, i xiphemu xo kwetsima swinene eka minyikelo ya ndzilo ya Yehovha.”' },
    { n: 4, text: '“Loko u tisa munyikelo wa xinkwa lowu bakiweke hi xikolo, wu ta va hi mapa lamamanene, mikwa ya xinkwa leyi nga riki na comela, leyi endliweke hi mafurha, kumbe xinkwa xo thyeka lexi nga riki na comela, lexi totiweke hi mafurha.”' },
    { n: 5, text: '“Loko munyikelo wa wena wu ri xinkwa lexi bakiweke epaneni, wu ta va wa mapa lamamanene, leyi nga riki na comela, leyi katsiweke hi mafurha.”' },
    { n: 6, text: '“U ta xi handzela swiphemu, u xi chela mafurha, i munyikelo wa xinkwa.”' },
    { n: 7, text: '“Loko munyikelo wa wena wu ri xinkwa lexi bakiweke endzeni ka xibya, wu ta endliwa hi mapa lamamanene hi mafurha.”' },
    { n: 8, text: '“U ta tisa munyikelo lowu endliweke hi swilo leswi eka Yehovha; a a xi tise eka muprista, a a xi tise ealitari.”' },
    { n: 9, text: '“Muprista a a teke xiphemu xa munyikelo wa xinkwa, a xi hisa ealitari, i munyikelo wa ndzilo, nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 10, text: '“Leswi swi salaka eka munyikelo wa xinkwa swi ta va swa Aroni ni vana va yena, i xiphemu xo kwetsima swinene eka minyikelo ya ndzilo ya Yehovha.”' },
    { n: 11, text: '“Hinkwaswo swinyikelo swa xinkwa leswi mi swi tisaka eka Yehovha, swi nga endliwi hi comela, hikuva mi nga hisi comela hambi ri ri mafurha ya tinyoxi, tanihi munyikelo wa ndzilo eka Yehovha.”' },
    { n: 12, text: '“Tanihi munyikelo wa swilo swa le masin’wini, mi nga swi tisa eka Yehovha, kambe swi nga tisiwi ealitari ku va nun’hwelo lowu tsakisaka.”' },
    { n: 13, text: '“Munyikelo hinkwawo wa xinkwa wa wena u ta wu chela munyu; u nga pfumali munyu wa ntwanano wa Xikwembu xa wena eka munyikelo wa wena; eka hinkwaswo swinyikelo swa wena u ta tisa munyu.”' },
    { n: 14, text: '“Loko u tisa munyikelo wa vukona byo sungula eka Yehovha, u ta tisa swirunhu leswi oxiweke endzilweni, swi pandziweke swi ri swintshwa, tanihi munyikelo wa vukona byo sungula.”' },
    { n: 15, text: '“U ta xi chela mafurha, u xi vekelela nun’hwelo wa swirungo; i munyikelo wa xinkwa.”' },
    { n: 16, text: '“Muprista a a hise xiphemu xa swona, ni swirungo swa swona, ni mafurha ya swona hinkwawo, i munyikelo wa ndzilo eka Yehovha.”' }
  ],
  3: [
    { n: 1, text: '“Loko munyikelo wa yena wu ri xitlhavelo xa ku rhula, loko a tisa hi tihomu, hambi xi ri xinuna hambi xi ri xisati, a a tise lexi nga riki na xilaveko mahlweni ka Yehovha.”' },
    { n: 2, text: '“A a be voko ra yena ehenhla ka nhloko ya munyikelo wa yena, a wu tlhavela emunyangweni wa tabernakela ya nhlanganiso; vana va Aroni, vaprista, va ta chela ngati ealitari ku rhendzela.”' },
    { n: 3, text: '“A a tise eka minyikelo ya ndzilo ya Yehovha mafurha lawa ma funengetaka marumbu, ni mafurha hinkwawo lawa ma nga ehenhla ka marumbu.”' },
    { n: 4, text: '“Ni tinsungwa timbirhi, ni mafurha lawa ma nga ehenhla ka tona, lawa ma nga kusuhi ni n’hwanga, ni le henhla ka xibindi, a a swi susa swi ri na marumbu.”' },
    { n: 5, text: '“Vana va Aroni va ta swi hisa ealitari ehenhla ka xitlhavelo xo hisiwa, lexi nga ehenhla ka tihunyi, i munyikelo wa ndzilo, nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 6, text: '“Loko munyikelo wa yena wa xitlhavelo xa ku rhula eka Yehovha wu ri wa tinyimpfu, hambi xinuna hambi xisati, a a tise lexi nga riki na xilaveko.”' },
    { n: 7, text: '“Loko a tisa xinyimpfu tanihi munyikelo wa yena, a a xi tise mahlweni ka Yehovha.”' },
    { n: 8, text: '“A a be voko ra yena ehenhla ka nhloko ya munyikelo wa yena, a xi tlhavela mahlweni ka tabernakela ya nhlanganiso; vana va Aroni va ta chela ngati ya xona ealitari ku rhendzela.”' },
    { n: 9, text: '“A a tise eka munyikelo wa ndzilo wa Yehovha mafurha ya xona; ncila hinkwawo, a a wu tsemela kusuhi ni n’hwanga, ni mafurha hinkwawo lawa ma funengetaka marumbu.”' },
    { n: 10, text: '“Ni tinsungwa timbirhi, ni mafurha lawa ma nga ehenhla ka tona, lawa ma nga kusuhi ni n’hwanga, ni le henhla ka xibindi, a a swi susa swi ri na marumbu.”' },
    { n: 11, text: '“Muprista a a swi hise ealitari, i swakudya swa munyikelo wa ndzilo eka Yehovha.”' },
    { n: 12, text: '“Loko munyikelo wa yena wu ri mbuti, a a yi tise mahlweni ka Yehovha.”' },
    { n: 13, text: '“A a be voko ra yena ehenhla ka nhloko ya yona, a yi tlhavela mahlweni ka tabernakela ya nhlanganiso; vana va Aroni va ta chela ngati ya yona ealitari ku rhendzela.”' },
    { n: 14, text: '“A a tise eka yona munyikelo wa yena, i munyikelo wa ndzilo eka Yehovha: mafurha lawa ma funengetaka marumbu, ni mafurha hinkwawo lawa ma nga ehenhla ka marumbu.”' },
    { n: 15, text: '“Ni tinsungwa timbirhi, ni mafurha lawa ma nga ehenhla ka tona, lawa ma nga kusuhi ni n’hwanga, ni le henhla ka xibindi, a a swi susa swi ri na marumbu.”' },
    { n: 16, text: '“Muprista a a swi hise ealitari, i swakudya swa munyikelo wa ndzilo, i nun’hwelo lowu tsakisaka. Mafurha hinkwawo i ya Yehovha.”' },
    { n: 17, text: '“I nawu wa vutomi lebyi nga heriki eka tinxaka ta n’wina etindhawini hinkwato ta n’wina: mi nga dyi mafurha hambi ri ri ngati.”' }
  ],
  4: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko munhu a dyoha hi xihoxo eka hinkwaswo leswi Yehovha a leriseke leswaku swi nga endliwi, a endla xin’wana xa swona...”' },
    { n: 3, text: '“Loko muprista la totiweke a dyoha, a tisa nandzu eka vanhu, a a tise eka Yehovha xihomu xa xinuna lexi nga riki na xilaveko hikwalaho ka xidyoho xa yena.”' },
    { n: 4, text: '“A a tise xihomu emunyangweni wa tabernakela ya nhlanganiso mahlweni ka Yehovha, a a be voko ra yena ehenhla ka nhloko ya xihomu, a xi tlhavela mahlweni ka Yehovha.”' },
    { n: 5, text: '“Muprista la totiweke a a teke ngati ya xihomu, a yi nghenisa etabernakela ya nhlanganiso.”' },
    { n: 6, text: '“Muprista a a nyikele voko ra yena engatini, a fafata ngati makhamba ya nhungu mahlweni ka Yehovha, mahlweni ka nkhombolo wa ku kwetsima.”' },
    { n: 7, text: '“Muprista a a chele ngati etimponjini ta alitari ya nun’hwelo wa swirungo leyi nga mahlweni ka Yehovha, leyi nga etabernakela ya nhlanganiso; ngati hinkwayo ya xihomu a a yi chululela emilengeni ya alitari ya xitlhavelo xo hisiwa, leyi nga emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 8, text: '“A a susa mafurha hinkwawo ya xihomu xa xidyoho: mafurha lawa ma funengetaka marumbu, ni mafurha hinkwawo lawa ma nga ehenhla ka marumbu.”' },
    { n: 9, text: '“Ni tinsungwa timbirhi, ni mafurha lawa ma nga ehenhla ka tona, lawa ma nga kusuhi ni n’hwanga, ni le henhla ka xibindi, a a swi susa swi ri na marumbu.”' },
    { n: 10, text: '“Hilaha swi susiweke hakona eka xihomu xa xitlhavelo xa ku rhula; muprista a a swi hise ealitari ya xitlhavelo xo hisiwa.”' },
    { n: 11, text: '“Kambe ntsumbu wa xihomu, ni nhloko ya xona, ni milenge ya xona, ni marumbu ya xona, ni xigadzi xa xona.”' },
    { n: 12, text: '“Xihomu hinkwaxo a a xi humese ehandle ka nkambi endhawini yo kwetsima, laha nkuma wu chuluriwaka, a a xi hisa ehenhla ka tihunyi leti nga endzilweni; laha nkuma wu chuluriwaka, hi kona laha xi nga ta hisiwa kona.”' },
    { n: 13, text: '“Loko nhlengeletano hinkwayo ya Israyele yi dyoha hi xihoxo, naswona mhaka yi fihleke mahlweni ka nhlengeletano, va endla xin’wana xa leswi Yehovha a leriseke leswaku swi nga endliwi, naswona va va ni nandzu.”' },
    { n: 14, text: '“Loko xidyoho lexi va xi endleke xi tiviwa, nhlengeletano a yi tise xihomu xa xinuna xa xidyoho, va xi tise mahlweni ka tabernakela ya nhlanganiso.”' },
    { n: 15, text: '“Vakulukumba va nhlengeletano va ta be voko ra vona ehenhla ka nhloko ya xihomu mahlweni ka Yehovha, va tlhavela xihomu mahlweni ka Yehovha.”' },
    { n: 16, text: '“Muprista la totiweke a a nghenise ngati ya xihomu etabernakela ya nhlanganiso.”' },
    { n: 17, text: '“Muprista a a nyikele voko ra yena engatini, a fafata ngati makhamba ya nhungu mahlweni ka Yehovha, mahlweni ka nkhombolo.”' },
    { n: 18, text: '“A a chele ngati etimponjini ta alitari leyi nga mahlweni ka Yehovha, leyi nga etabernakela ya nhlanganiso; ngati hinkwayo a a yi chululela emilengeni ya alitari ya xitlhavelo xo hisiwa, leyi nga emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 19, text: '“A a susa mafurha ya xona hinkwawo, a a swi hise ealitari.”' },
    { n: 20, text: '“A a endle hi xihomu hi laha a endleke hakona hi xihomu xa xidyoho; muprista a a va endlele mukutsulo, va ta rivaleriwa.”' },
    { n: 21, text: '“A a humese xihomu ehandle ka nkambi, a a xi hise hilaha a hiseke xihomu xo sungula hakona; i xidyoho xa nhlengeletano.”' },
    { n: 22, text: '“Loko ndhuna yi dyoha, yi endla hi xihoxo xin’wana xa swilo hinkwaswo leswi Yehovha a leriseke leswaku swi nga endliwi, naswona yi va ni nandzu.”' },
    { n: 23, text: '“Loko xidyoho xa yona lexi yi xi endleke xi tiviwa, yi ta tisa munyikelo wa yona, mbuti ya xinuna leyi nga riki na xilaveko.”' },
    { n: 24, text: '“Yi ta be voko ra yona ehenhla ka nhloko ya mbuti, yi yi tlhavela laha ku tlhaviwaka xitlhavelo xo hisiwa mahlweni ka Yehovha; i xidyoho.”' },
    { n: 25, text: '“Muprista a a teke ngati ya xidyoho hi munwe wa yena, a a yi chele etimponjini ta alitari ya xitlhavelo xo hisiwa, ngati leyi saleke a a yi chululela emilengeni ya alitari ya xitlhavelo xo hisiwa.”' },
    { n: 26, text: '“A a hise mafurha hinkwawo ealitari hilaha a hiseke mafurha ya xitlhavelo xa ku rhula; muprista a a yi endlele mukutsulo hikwalaho ka xidyoho xa yona, yi ta rivaleriwa.”' },
    { n: 27, text: '“Loko un’wana wa vanhu va tiko a dyoha hi xihoxo, a endla xin’wana xa swilo leswi Yehovha a leriseke leswaku swi nga endliwi, naswona a va ni nandzu.”' },
    { n: 28, text: '“Loko xidyoho xa yena lexi a xi endleke xi tiviwa, a a tise munyikelo wa yena, mbuti ya xisati leyi nga riki na xilaveko, hikwalaho ka xidyoho xa yena.”' },
    { n: 29, text: '“A a be voko ra yena ehenhla ka nhloko ya xidyoho, a xi tlhavela laha ku tlhaviwaka xitlhavelo xo hisiwa.”' },
    { n: 30, text: '“Muprista a a teke ngati ya yona hi munwe wa yena, a a yi chele etimponjini ta alitari ya xitlhavelo xo hisiwa, ngati hinkwayo leyi saleke a a yi chululela emilengeni ya alitari.”' },
    { n: 31, text: '“A a susa mafurha ya yona hinkwawo hilaha a susiweke hakona mafurha ya xitlhavelo xa ku rhula; muprista a a swi hise ealitari, i nun’hwelo lowu tsakisaka Yehovha; muprista a a yi endlele mukutsulo, yi ta rivaleriwa.”' },
    { n: 32, text: '“Loko a tisa xinyimpfu tanihi munyikelo wa xidyoho, a a tise xisati lexi nga riki na xilaveko.”' },
    { n: 33, text: '“A a be voko ra yena ehenhla ka nhloko ya xidyoho, a xi tlhavela laha ku tlhaviwaka xitlhavelo xo hisiwa.”' },
    { n: 34, text: '“Muprista a a teke ngati ya xidyoho hi munwe wa yena, a a yi chele etimponjini ta alitari ya xitlhavelo xo hisiwa, ngati hinkwayo leyi saleke a a yi chululela emilengeni ya alitari.”' },
    { n: 35, text: '“A a susa mafurha hinkwawo hilaha a susiweke hakona mafurha ya xinyimpfu xa xitlhavelo xa ku rhula; muprista a a swi hise ealitari ehenhla ka minyikelo ya ndzilo ya Yehovha; muprista a a yi endlele mukutsulo hikwalaho ka xidyoho xa yona, yi ta rivaleriwa.”' }
  ],
  5: [
    { n: 1, text: '“Loko munhu a twa xihlambanyo xa ku pfumala nandzu, naswona a ri mboni, hikuva u vone kumbe u tivile, kambe a nga vuli ntiyiso, u ta rhwala nandzu wa yena.”' },
    { n: 2, text: '“Loko munhu a khumba nchumu wun’wana lowu nga tengangiki, hambi ku ri ntsumbu wa xivandzana lexi nga tengangiki, hambi ku ri ntsumbu wa xifuwo, naswona a nga swi tivi, u ta va ni nandzu.”' },
    { n: 3, text: '“Loko a khumba nchumu wa munhu lowu nga tengangiki, naswona a swi tiva, u ta va ni nandzu.”' },
    { n: 4, text: '“Loko munhu a hlambanya hi nomu wa yena ku endla swo biha kumbe swa kahle, hinkwaswo leswi munhu a hlambanyaka hi swona, naswona a nga swi tivi, u ta va ni nandzu.”' },
    { n: 5, text: '“Loko a va ni nandzu eka xin’wana xa leswi, a a pfumele xidyoho xa yena.”' },
    { n: 6, text: '“A a tise munyikelo wa yena eka Yehovha hikwalaho ka xidyoho xa yena, xisati xa ntlhambi, xinyimpfu kumbe mbuti tanihi xidyoho; muprista a a yi endlele mukutsulo hikwalaho ka xidyoho xa yona.”' },
    { n: 7, text: '“Loko a nga ri na mali yo xava xinyimpfu, a a tise tanihi munyikelo wa nandzu wa yena, tinyenyana timbirhi, tinjiwa kumbe swiwa-tiva, hi mun’we wa xidyoho, ni wun’wana wa xitlhavelo xo hisiwa.”' },
    { n: 8, text: '“A a tise eka muprista, muprista a a hlayi nhloko ya le mahlweni, a nga yi hambanisi.”' },
    { n: 9, text: '“A a fafata ngati ya xidyoho etlhelweni ra alitari, ngati leyi saleke a a yi kamyuriwa emilengeni ya alitari, i xidyoho.”' },
    { n: 10, text: '“A a endle ya vumbirhi tanihi xitlhavelo xo hisiwa hilaha swi lerisiweke hakona; muprista a a yi endlele mukutsulo hikwalaho ka xidyoho xa yona, yi ta rivaleriwa.”' },
    { n: 11, text: '“Loko a nga ri na mali ya tinyenyana timbirhi, a a tise munyikelo wa yena, wa mapa lamamanene, wa xiphemu xa vukhume xa efa, hikwalaho ka xidyoho xa yena; a nga wu cheli mafurha, hambi ku ri nun’hwelo wa swirungo, hikuva i xidyoho.”' },
    { n: 12, text: '“A a tise eka muprista, muprista a a teke ndzalo wa voko ra yena eka wona, a xi hisa ealitari, i munyikelo wa ndzilo eka Yehovha; i xidyoho.”' },
    { n: 13, text: '“Muprista a a yi endlele mukutsulo hikwalaho ka xidyoho xa yona, yi ta rivaleriwa; leswi swi salaka swi ta va swa muprista tanihi munyikelo wa xinkwa.”' },
    { n: 14, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 15, text: '“Loko munhu a dyoha, a endla xidyoho hi xihoxo eka swilo swo kwetsima swa Yehovha, a a tise munyikelo wa yena eka Yehovha, xikontiri xa tinyimpfu lexi nga riki na xilaveko, hi mali ya xiketelelo.”' },
    { n: 16, text: '“A a teke leswi a dyohereke ha swona eka swilo swo kwetsima, a a engetela xa ntlhanu eka swona, a a swi nyikela eka muprista; muprista a a yi endlele mukutsulo hi xikontiri xa xidyoho, yi ta rivaleriwa.”' },
    { n: 17, text: '“Loko munhu a dyoha, a endla xin’wana xa swilo leswi Yehovha a leriseke leswaku swi nga endliwi, hambi a nga swi tivi, u ta va ni nandzu, u ta rhwala nandzu wa yena.”' },
    { n: 18, text: '“A a tise eka muprista xikontiri xa tinyimpfu lexi nga riki na xilaveko, tanihi munyikelo wa nandzu; muprista a a yi endlele mukutsulo hi xidyoho lexi a xi endleke hi xihoxo, yi ta rivaleriwa.”' },
    { n: 19, text: '“I munyikelo wa nandzu, u dyohile eka Yehovha.”' }
  ],
  6: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Loko munhu a dyoha, a endla xidyoho eka Yehovha, a hemba mutsongo wa yena eka nchumu lowu a wu vekiweke eka yena, kumbe eka nchumu lowu a yiviweke, kumbe a kanganyisa mutsongo wa yena...”' },
    { n: 3, text: '“Kumbe a kume nchumu lowu lahlekiweke, a hemba eka wona, a hlambanya hi mavunwa; eka hinkwaswo leswi munhu a swi endlaka, a dyoha ha swona...”' },
    { n: 4, text: '“Loko a dyohile a va ni nandzu, a a tlherise nchumu lowu a wu yiveke, kumbe nchumu lowu a wu kanganyiseke, kumbe nchumu lowu a wu vekiweke eka yena, kumbe nchumu lowu lahlekiweke lowu a wu kumeke...”' },
    { n: 5, text: '“Kumbe hinkwaswo leswi a hlambanyeke hi mavunwa eka swona; a a swi tlherise hi ku helela, a a engetela xa ntlhanu eka swona, a a swi nyikela eka n’wini wa swona hi siku ra munyikelo wa nandzu wa yena.”' },
    { n: 6, text: '“A a tise munyikelo wa yena wa nandzu eka Yehovha, xikontiri xa tinyimpfu lexi nga riki na xilaveko, hi mali ya xiketelelo, a a swi nyikela eka muprista.”' },
    { n: 7, text: '“Muprista a a yi endlele mukutsulo mahlweni ka Yehovha; yi ta rivaleriwa eka hinkwaswo leswi munhu a swi endleke a va ni nandzu.”' },
    { n: 8, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 9, text: '“Lerisa Aroni ni vana va yena, u ku: I nawu wa xitlhavelo xo hisiwa: Xitlhavelo xo hisiwa xi ta va ehenhla ka ndzilo ealitari vusiku hinkwabyo ku fikela nimixo, naswona ndzilo wa alitari wu ta va wu pfurha eka yona.”' },
    { n: 10, text: '“Muprista a a ambale tinguvu ta le henhla ta rihanyo, a ambale tinguvu ta le ndzeni ehenhla ka miri wa yena, a susa nkuma lowu ndzilo wu wu hiseke eka xitlhavelo xo hisiwa ealitari, a a wu veka etlhelweni ra alitari.”' },
    { n: 11, text: '“A a hluvula tinguvu ta yena, a ambara tinguvu tin’wana, a a humesa nkuma ehandle ka nkambi endhawini yo tenga.”' },
    { n: 12, text: '“Ndzilo ealitari wu ta va wu pfurha, wu nga timi; muprista a a hlela tihunyi ehenhla ka wona nimixo ni nimixo, a a hlela xitlhavelo xo hisiwa ehenhla ka wona, a a hisa mafurha ya xitlhavelo xa ku rhula.”' },
    { n: 13, text: '“Ndzilo wu ta va wu pfurha minkarhi hinkwayo ealitari, wu nga timi.”' },
    { n: 14, text: '“I nawu wa munyikelo wa xinkwa: Vana va Aroni va ta wu tisa mahlweni ka Yehovha, mahlweni ka alitari.”' },
    { n: 15, text: '“A a teke ndzalo wa voko ra yena hi mapa ya wona, ni mafurha ya wona, ni nun’hwelo hinkwawo wa swirungo, a a swi hise ealitari, i nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 16, text: '“Leswi swi salaka eka wona, Aroni ni vana va yena va ta swi dya; va ta swi dya swi ri swinkwa swi nga riki na comela endhawini yo kwetsima, va ta swi dyela erivaleni ra tabernakela ya nhlanganiso.”' },
    { n: 17, text: '“A swi bakiwi swi ri na comela; ndzi swi nyikile tanihi xiphemu xa minyikelo ya ndzilo ya mina; i xo kwetsima swinene, ku fana ni xidyoho ni munyikelo wa nandzu.”' },
    { n: 18, text: '“Vaxinuna hinkwavo exikarhi ka vana va Aroni va ta swi dya; i nawu wa vutomi lebyi nga heriki eka tinxaka ta n’wina eka minyikelo ya ndzilo ya Yehovha: Hinkwaswo leswi swi khumbaka swi ta va swo kwetsima.”' },
    { n: 19, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 20, text: '“I munyikelo wa Aroni ni vana va yena, lowu va nga ta wu tisa eka Yehovha hi siku leri a totiwaka ha rona: xiphemu xa vukhume xa efa ra mapa lamamanene tanihi munyikelo wa xinkwa, n’we-xa-nhungu nimixo, ni n’we-xa-nhungu ni madyambu.”' },
    { n: 21, text: '“A a swi endle hi mafurha epaneni, swi ri swi oxiweke a a swi tise, i swiphemu swa xinkwa xa nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 22, text: '“Muprista la totiweke exikarhi ka vana va yena a a swi tise; i nawu wa vutomi lebyi nga heriki eka Yehovha, swi ta hisiwa hi ku helela.”' },
    { n: 23, text: '“Munyikelo hinkwawo wa xinkwa wa muprista wu ta hisiwa hi ku helela; wu nga dyiwi.”' },
    { n: 24, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 25, text: '“Vulavula ni Aroni ni vana va yena, u ku: I nawu wa xidyoho: Endhawini leyi ku tlhaviwaka xitlhavelo xo hisiwa, hi kona laha xidyoho xi nga ta tlhaviwaka mahlweni ka Yehovha; i xo kwetsima swinene.”' },
    { n: 26, text: '“Muprista la endlaka xidyoho a a xi dya; xi ta dyeriwa endhawini yo kwetsima, erivaleni ra tabernakela ya nhlanganiso.”' },
    { n: 27, text: '“Hinkwaswo leswi swi khumbaka nyama ya xona swi ta va swo kwetsima; loko ngati ya xona yi fafateka eka tinguvu, u ta hlantswa leyi yi fafateke endhawini yo kwetsima.”' },
    { n: 28, text: '“Xibya xa vumba lexi xi hlambaka xi xi hlamulaka, a xi fanele xi tshoviwa; loko xi ri xibya xa nsuku, xi fanele xi hlantswiwa hi mati.”' },
    { n: 29, text: '“Vaxinuna hinkwavo exikarhi ka vaprista va ta xi dya; i xo kwetsima swinene.”' },
    { n: 30, text: '“Kambe xidyoho xin’wana ni xin’wana, lexi ngati ya xona yi nghenisiwaka etabernakela ya nhlanganiso ku endla mukutsulo endhawini yo kwetsima, a xi dyiwi; xi ta hisiwa hi ndzilo.”' }
  ],
  7: [
    { n: 1, text: '“Leswi i nawu wa xitlhavelo xa nandzu: i xo kwetsima swinene.”' },
    { n: 2, text: '“Xitlhavelo xa nandzu xi ta tlhaveriwa laha ku tlhaviwaka xitlhavelo xo hisiwa, naswona vaprista va ta chela ngati ya xona ealitari ku rhendzela.”' },
    { n: 3, text: '“A a tise mafurha hinkwawo ya xona, ni ncila, ni mafurha lawa ma funengetaka marumbu.”' },
    { n: 4, text: '“Ni tinsungwa timbirhi, ni mafurha lawa ma nga ehenhla ka tona, lawa ma nga kusuhi ni n’hwanga, ni le henhla ka xibindi, a a swi susa swi ri na marumbu.”' },
    { n: 5, text: '“Muprista a a swi hise ealitari, i munyikelo wa ndzilo eka Yehovha; i xitlhavelo xa nandzu.”' },
    { n: 6, text: '“Vaxinuna hinkwavo exikarhi ka vaprista va ta xi dya; xi ta dyeriwa endhawini yo kwetsima, i xo kwetsima swinene.”' },
    { n: 7, text: '“Xitlhavelo xa nandzu xi fana ni xidyoho; nawu wa swona i wun’we: i xa muprista la endlaka mukutsulo ha xona.”' },
    { n: 8, text: '“Muprista la nyikelaka xitlhavelo xo hisiwa xa munhu, nkumba wa xitlhavelo xo hisiwa wu ta va wa muprista.”' },
    { n: 9, text: '“Munyikelo hinkwawo wa xinkwa lowu bakiweke epaneni, kumbe eka xibya, kumbe epaneni ro tsetselela, wu ta va wa muprista.”' },
    { n: 10, text: '“Munyikelo hinkwawo wa xinkwa, hambi wu katsiwe hi mafurha kumbe wu pfumala, wu ta va wa vana hinkwavo va Aroni, va wu averana.”' },
    { n: 11, text: '“I nawu wa xitlhavelo xa ku rhula lexi munhu a xi tisaka eka Yehovha.”' },
    { n: 12, text: '“Loko a xi tisa hikwalaho ka ku nkhensa, a a tise ni xinkwa xo pfumala comela lexi katsiweke hi mafurha, ni swinkwa swa mivala-vala leswi totiweke hi mafurha, ni mapa lamamanene lama katsiweke hi mafurha.”' },
    { n: 13, text: '“Ehenhla ka xinkwa xo pfumala comela, a a tise munyikelo wa yena wa xinkwa xa comela eka xitlhavelo xa ku rhula.”' },
    { n: 14, text: '“A a tise xiphemu xin’we xa minyikelo hinkwayo tanihi munyikelo eka Yehovha; xi ta va xa muprista la cheleke ngati ya xitlhavelo xa ku rhula.”' },
    { n: 15, text: '“Nyama ya xitlhavelo xa ku rhula lexi nkhenso xi ta dyeriwa hi siku ra munyikelo wa xona; va nga tshiki nchumu wu sala ku fikela nimixo.”' },
    { n: 16, text: '“Loko xitlhavelo xa yena xi ri xitshembiso kumbe munyikelo wa ku tirhandzela, xi ta dyeriwa hi siku leri a xi nyikelaka ha rona; leswi swi salaka swi ta dyeriwa hi siku ra le ndzhaku.”' },
    { n: 17, text: '“Kambe leswi swi salaka eka nyama ya xitlhavelo hi siku ra vunharhu swi ta hisiwa hi ndzilo.”' },
    { n: 18, text: '“Loko munhu a dya nyama ya xitlhavelo xa ku rhula hi siku ra vunharhu, xi nga ta amukeleka, xi ta va xi ri nchumu lowu nyamisaka; munhu la dyaka a ta rhwala nandzu wa yena.”' },
    { n: 19, text: '“Nyama leyi khumbaka nchumu lowu nga tengangiki a yi dyiwi; yi ta hisiwa hi ndzilo. Loko a ri nyama yo tenga, hinkwavo lava va tengeke va ta dya nyama.”' },
    { n: 20, text: '“Munhu la dyaka nyama ya xitlhavelo xa ku rhula eka Yehovha, naswona a ri ni nandzu, u ta susiwa exikarhi ka vanhu va yena.”' },
    { n: 21, text: '“Munhu la khumbaka nchumu lowu nga tengangiki, hambi ri ri nchumu wa munhu kumbe wa xivandzana, naswona a dya nyama ya xitlhavelo xa ku rhula, u ta susiwa exikarhi ka vanhu va yena.”' },
    { n: 22, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 23, text: '“Vulavula ni vana va Israyele, u ku: Mi nga dyi mafurha ya xihomu, hambi ya xinyimpfu, hambi ya mbuti.”' },
    { n: 24, text: '“Mafurha ya xivandzana lexi feke, ni mafurha ya lexi xaxameke, ma nga tirhisiwa eka ntirho wun’wana, kambe ma nga dyiwi.”' },
    { n: 25, text: '“Hikuva un’wana ni un’wana la dyaka mafurha ya swifuwo, munhu la dyaka a ta susiwa exikarhi ka vanhu va yena.”' },
    { n: 26, text: '“Mi nga dyi ngati etindhawini hinkwato ta n’wina, hambi ya tinyenyana hambi ya swifuwo.”' },
    { n: 27, text: '“Un’wana ni un’wana la dyaka ngati, munhu la dyaka a ta susiwa exikarhi ka vanhu va yena.”' },
    { n: 28, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 29, text: '“Vulavula ni vana va Israyele, u ku: La nyikelaka xitlhavelo xa ku rhula eka Yehovha, a a tise munyikelo wa yena eka Yehovha.”' },
    { n: 30, text: '“A a tise hi mavoko ya yena minyikelo ya ndzilo ya Yehovha; mafurha ni ncila a a swi tise, leswaku xi nyikelwa mahlweni ka Yehovha.”' },
    { n: 31, text: '“Muprista a a hise mafurha ealitari, ncila wu ta va wa Aroni ni vana va yena.”' },
    { n: 32, text: '“Xiphemu xa xinene xa xitlhavelo xa ku rhula mi ta xi nyika muprista.”' },
    { n: 33, text: '“La nyikelaka ngati ni mafurha ya xitlhavelo xa ku rhula exikarhi ka vana va Aroni, a a teke xiphemu xa xinene tanihi xiphemu xa yena.”' },
    { n: 34, text: '“Hikuva xiphemu xa xinene ni nkumba wa munyikelo, ndzi swi teke eka vana va Israyele, eka switlhavelo swa ku rhula, ndzi swi nyika Aroni muprista ni vana va yena tanihi nawu wa vutomi lebyi nga heriki.”' },
    { n: 35, text: '“Leswi i xiphemu xa Aroni ni vana va yena eka minyikelo ya ndzilo ya Yehovha, hi siku leri a va vitaneleke ha rona ku va vaprista eka Yehovha.”' },
    { n: 36, text: '“Leswi Yehovha a leriseke leswaku va nyikiwa hi vana va Israyele hi siku leri a va totikeke ha rona; i nawu wa vutomi lebyi nga heriki eka tinxaka ta n’wina.”' },
    { n: 37, text: '“I nawu wa xitlhavelo xo hisiwa, ni munyikelo wa xinkwa, ni xidyoho, ni munyikelo wa nandzu, ni xitlhavelo xa ku totiwa, ni xitlhavelo xa ku rhula.”' },
    { n: 38, text: '“Lowu Yehovha a leriseke Moxe eGavana ra Sinayi, hi siku leri a leriseke vana va Israyele ku tisa minyikelo ya vona eka Yehovha, eGavana ra Sinayi.”' }
  ],
  8: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Tekani Aroni ni vana va yena, ni tinguvu, ni mafurha ya ku tota, ni xihomu xa xidyoho, ni tinyimpfu timbirhi, ni xinkwa xo pfumala comela.”' },
    { n: 3, text: '“Hlengeletani vana va Israyele hinkwavo emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 4, text: '“Moxe a endla hilaha Yehovha a leriseke hakona, naswona vanhu va hlengeletana emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 5, text: '“Moxe a ku eka vanhu: Leswi Yehovha a leriseke leswaku swi endliwa, hi leswi.”' },
    { n: 6, text: '“Moxe a tisa Aroni ni vana va yena, a va hlantswa hi mati.”' },
    { n: 7, text: '“A a ambexa Aroni tinguvu, a a boha mukhandi, a a ambexa tinguvu ta le henhla, a a ambexa efoda, a a boha efoda hi xinkhubyane xa yona.”' },
    { n: 8, text: '“A a veka xifuva hi xifuva, a a veka Urim ni Tumim eka xifuva.”' },
    { n: 9, text: '“A a veka xihandla ehenhla ka nhloko ya Aroni, a a veka xifunengeto xa nsuku ehenhla ka xihandla, i xihandla xo kwetsima, hilaha Yehovha a leriseke Moxe.”' },
    { n: 10, text: '“Moxe a teka mafurha ya ku tota, a tota tabernakela ni hinkwaswo leswi nga endzeni, a swi kwetsimisa.”' },
    { n: 11, text: '“A a fafata alitari makhamba ya nhungu, a a tota alitari ni swibye swa yona hinkwaswo, ni xibye xa mati ni xisekelo xa xona, a a swi kwetsimisa.”' },
    { n: 12, text: '“A a chela mafurha ya ku tota ehenhla ka nhloko ya Aroni, a a n’wi tota leswaku a va muprista.”' },
    { n: 13, text: '“Moxe a tisa vana va Aroni, a va ambexa tinguvu, a a boha mukhandi, a a va boha swihandla, hilaha Yehovha a leriseke Moxe.”' },
    { n: 14, text: '“A a tisa xihomu xa xidyoho, Aroni ni vana va yena va ta be mavoko ya vona ehenhla ka nhloko ya xihomu xa xidyoho.”' },
    { n: 15, text: '“Moxe a a tlhave xihomu, a a teke ngati, a a chela etimponjini ta alitari ku rhendzela hi munwe wa yena, a a kwetsimisa alitari; ngati leyi saleke a a yi chululela emilengeni ya alitari, a a yi kwetsimisa ku endla mukutsulo.”' },
    { n: 16, text: '“A a teke mafurha hinkwawo lawa ma nga ehenhla ka marumbu, ni xigadzi xa xibindi, ni tinsungwa timbirhi, ni mafurha ya tona, Moxe a a swi hise ealitari.”' },
    { n: 17, text: '“Kambe xihomu, ni nkumba wa xona, ni nyama ya xona, ni xigadzi xa xona, a a xi hisa hi ndzilo ehandle ka nkambi, hilaha Yehovha a leriseke Moxe.”' },
    { n: 18, text: '“A a tisa xinyimpfu xa xitlhavelo xo hisiwa, Aroni ni vana va yena va ta be mavoko ya vona ehenhla ka nhloko ya xinyimpfu.”' },
    { n: 19, text: '“Moxe a a xi tlhave, a a chela ngati ealitari ku rhendzela.”' },
    { n: 20, text: '“A a tsema xinyimpfu hi swiphemu, Moxe a a hisa nhloko, ni swiphemu, ni mafurha.”' },
    { n: 21, text: '“A a hlantswa marumbu ya xona ni milenge ya xona hi mati, Moxe a a hisa xinyimpfu hinkwaxo ealitari, i xitlhavelo xo hisiwa, nun’hwelo lowu tsakisaka Yehovha, hilaha Yehovha a leriseke Moxe.”' },
    { n: 22, text: '“A a tisa xinyimpfu xa vumbirhi, xinyimpfu xa ku totiwa, Aroni ni vana va yena va ta be mavoko ya vona ehenhla ka nhloko ya xinyimpfu.”' },
    { n: 23, text: '“Moxe a a xi tlhave, a a teke ngati, a a chela etimponjini ta tindleve ta Aroni, ni le vukolweni bya voko ra yena ra xinene, ni le xipeni xa nenge wa yena wa xinene.”' },
    { n: 24, text: '“A a tisa vana va Aroni, a a chela ngati etimponjini ta tindleve ta vona, ni le vukolweni bya voko ra vona ra xinene, ni le xipeni xa nenge wa vona wa xinene; Moxe a a chela ngati ealitari ku rhendzela.”' },
    { n: 25, text: '“A a teke mafurha, ni ncila, ni mafurha hinkwawo lawa ma nga ehenhla ka marumbu, ni xigadzi xa xibindi, ni tinsungwa timbirhi, ni mafurha ya tona, ni xinkhubyane xa voko ra xinene.”' },
    { n: 26, text: '“Naswona ehenhla ka xinkwa xo pfumala comela, lexi nga mahlweni ka Yehovha, a a teke xinkwa xin’we xo pfumala comela, ni xinkwa xin’we lexi katsiweke hi mafurha, ni xinkhubyane xin’we, a a swi veka ehenhla ka mafurha, ni le henhla ka xipeni xa voko ra xinene.”' },
    { n: 27, text: '“A a swi veka hinkwaswo emavokweni ya Aroni ni emavokweni ya vana va yena, a a swi nyikela tanihi munyikelo mahlweni ka Yehovha.”' },
    { n: 28, text: '“Moxe a a swi teka emavokweni ya vona, a a swi hisa ealitari ehenhla ka xitlhavelo xo hisiwa; i xitlhavelo xa ku totiwa, nun’hwelo lowu tsakisaka Yehovha.”' },
    { n: 29, text: '“Moxe a a teke xipeni, a a xi nyikela tanihi munyikelo mahlweni ka Yehovha; xi ta va xa Moxe tanihi xiphemu xa yena, hilaha Yehovha a leriseke Moxe.”' },
    { n: 30, text: '“Moxe a a teke mafurha ya ku tota, ni ngati leyi nga ealitari, a a fafata Aroni ni tinguvu ta yena, ni vana va yena ni tinguvu ta vona, a a kwetsimisa Aroni ni tinguvu ta yena, ni vana va yena ni tinguvu ta vona.”' },
    { n: 31, text: '“Moxe a ku eka Aroni ni vana va yena: Phekayani nyama emunyangweni wa tabernakela ya nhlanganiso, mi ta dyela kona, ni xinkwa lexi nga emunyangweni wa munyikelo, hilaha ndzi leriseke hakona: Aroni ni vana va yena va ta dya.”' },
    { n: 32, text: '“Leswi swi salaka eka nyama ni xinkwa mi ta swi hisa hi ndzilo.”' },
    { n: 33, text: '“Mi nga humi emunyangweni wa tabernakela ya nhlanganiso masiku ya nhungu, ku fikela siku leri ku hetiwaka masiku ya ku totiwa ka n’wina, hikuva u ta totiwa masiku ya nhungu.”' },
    { n: 34, text: '“Hilaha swi endliweke hakona hi siku leri, Yehovha u lerise leswaku ku endliwa mukutsulo wa n’wina.”' },
    { n: 35, text: '“Mi ta tshama emunyangweni wa tabernakela ya nhlanganiso masiku ya nhungu, nhlekanhi ni vusiku, mi hlayisa swileriso swa Yehovha, leswaku mi nga fi; hikuva ndzi lerisiwile.”' },
    { n: 36, text: '“Aroni ni vana va yena va endla hinkwaswo leswi Yehovha a leriseke hi Moxe.”' }
  ],
  9: [
    { n: 1, text: 'Hi siku ra vunhungu, Moxe a vitana Aroni ni vana va yena, ni vakulukumba va Israyele,' },
    { n: 2, text: 'a ku eka Aroni: “Tekanyani xihomu xa xinuna xa xidyoho, ni xitlhavelo xo hisiwa lexi nga riki na xilaveko, mi swi tisa mahlweni ka Yehovha.”' },
    { n: 3, text: '“Vulavula ni vana va Israyele, u ku: Tekanyani mpongo wa xidyoho, ni xihomu, ni xinyimpfu, leswi nga riki na xilaveko, swa xitlhavelo xo hisiwa.”' },
    { n: 4, text: '“Ni xihomu xa xinuna ni xinyimpfu xa xitlhavelo xa ku rhula, mi swi tlhavela mahlweni ka Yehovha, ni munyikelo wa xinkwa lowu katsiweke hi mafurha; hikuva namuntlha Yehovha u ta humelela eka n’wina.”' },
    { n: 5, text: '“Va tisa leswi Moxe a leriseke eka tabernakela ya nhlanganiso; nhlengeletano hinkwayo yi tshinela yi yima mahlweni ka Yehovha.”' },
    { n: 6, text: '“Moxe a ku: Leswi Yehovha a leriseke leswaku mi swi endla, naswona ku kwetsima ka Yehovha ku ta humelela eka n’wina.”' },
    { n: 7, text: '“Moxe a ku eka Aroni: Tshinela ealitari, u endla xidyoho xa wena ni xitlhavelo xo hisiwa xa wena, u endla mukutsulo wa wena ni wa vanhu, u endla munyikelo wa vanhu, u va endlela mukutsulo, hilaha Yehovha a leriseke hakona.”' },
    { n: 8, text: '“Aroni a tshinela ealitari, a tlhavela xihomu xa xidyoho xa yena.”' },
    { n: 9, text: '“Vana va Aroni va tisa ngati eka yena, a a chela ngati etimponjini ta alitari hi munwe wa yena, ngati leyi saleke a a yi chululela emilengeni ya alitari.”' },
    { n: 10, text: '“A a hisa mafurha, ni tinsungwa, ni xigadzi xa xibindi xa xidyoho ealitari, hilaha Yehovha a leriseke Moxe.”' },
    { n: 11, text: '“Nyama ni nkumba a a swi hisa hi ndzilo ehandle ka nkambi.”' },
    { n: 12, text: '“A a tlhavela xitlhavelo xo hisiwa; vana va Aroni va tisa ngati eka yena, a a yi chela ealitari ku rhendzela.”' },
    { n: 13, text: '“Va tisa xitlhavelo xo hisiwa eka yena hi swiphemu swa xona, ni nhloko, a a swi hisa ealitari.”' },
    { n: 14, text: '“A a hlantswa marumbu ya xona ni milenge ya xona, a a hisa ealitari ehenhla ka xitlhavelo xo hisiwa.”' },
    { n: 15, text: '“A a tisa munyikelo wa vanhu, a a teke mpongo wa xidyoho wa vanhu, a a wu tlhavela, a a wu endlela xidyoho hilaha a endleke hakona xo sungula.”' },
    { n: 16, text: '“A a tisa xitlhavelo xo hisiwa, a a xi endla hilaha nawu wu hlayaka hakona.”' },
    { n: 17, text: '“A a tisa munyikelo wa xinkwa, a a teke ndzalo wa voko ra yena, a a xi hisa ealitari ehenhla ka xitlhavelo xo hisiwa xa nimixo.”' },
    { n: 18, text: '“A a tlhavela xihomu ni xinyimpfu swa xitlhavelo xa ku rhula swa vanhu; vana va Aroni va tisa ngati eka yena, a a yi chela ealitari ku rhendzela.”' },
    { n: 19, text: '“Mafurha ya xihomu, ni ncila, ni mafurha lawa ma nga ehenhla ka marumbu, ni tinsungwa, ni xigadzi xa xibindi.”' },
    { n: 20, text: '“Va veka mafurha ehenhla ka tinsungwa, a a hisa mafurha ealitari.”' },
    { n: 21, text: '“Xipeni ni nenge wa xinene, Aroni a a swi nyikela tanihi munyikelo mahlweni ka Yehovha, hilaha Moxe a leriseke hakona.”' },
    { n: 22, text: '“Aroni a tlakusa mavoko ya yena eka vanhu, a va kateka, a rhela eka xidyoho, ni xitlhavelo xo hisiwa, ni xitlhavelo xa ku rhula.”' },
    { n: 23, text: '“Moxe ni Aroni va nghena etabernakela ya nhlanganiso, va huma va kateka vanhu; ku kwetsima ka Yehovha ku humelela eka vanhu hinkwavo.”' },
    { n: 24, text: '“Ndzilo wu huma mahlweni ka Yehovha, wu hisa ealitari xitlhavelo xo hisiwa ni mafurha; vanhu hinkwavo va swi vona, va huwelela va wela ehansi hi mbilu ya vona.”' }
  ],
  10: [
    { n: 1, text: '“Vana va Aroni, Nadab ni Abihu, va teka swibya swa vona swa ndzilo, va veka ndzilo eka swona, va veka nun’hwelo ehenhla ka wona, va tisa ndzilo lowu nga riki wa nawu mahlweni ka Yehovha, lowu a nga va lerisangiki.”' },
    { n: 2, text: '“Ndzilo wu huma mahlweni ka Yehovha, wu va hisa, va fela mahlweni ka Yehovha.”' },
    { n: 3, text: '“Moxe a ku eka Aroni: Leswi Yehovha a swi vuleke, a ku: Ndzi ta kwetsimisiwa hi lava va tshinelaka eka mina, naswona ndzi ta dzunisiwa mahlweni ka vanhu hinkwavo. Aroni a miyela.”' },
    { n: 4, text: '“Moxe a vitana Mixaele ni Elisafani, vana va Uziyela, hosi ya Aroni, a ku eka vona: Tshinelani, mi humesa vamakwenu emunyangweni wa ndhawu yo kwetsima, mi va humesa ehandle ka nkambi.”' },
    { n: 5, text: '“Va tshinela va va humesa hi tinguvu ta vona ehandle ka nkambi, hilaha Moxe a vuleke hakona.”' },
    { n: 6, text: '“Moxe a ku eka Aroni ni vana va yena Eleazara ni Itamara: Mi nga ambarisani mihloko, mi nga hluvuli tinguvu ta n’wina, leswaku mi nga fi, naswona vukarhi bya yena byi nga humeleli eka nhlengeletano hinkwayo; kambe vamakwenu, yindlu hinkwayo ya Israyele, va ta rila lava hisiweke hi ndzilo wa Yehovha.”' },
    { n: 7, text: '“Mi nga humi emunyangweni wa tabernakela ya nhlanganiso, leswaku mi nga fi, hikuva mafurha ya ku tota ya Yehovha ma le henhla ka n’wina; va endla hilaha Moxe a vuleke hakona.”' },
    { n: 8, text: 'Yehovha a vulavula na Aroni, a ku:' },
    { n: 9, text: '“Mi nga nwi vhinyo hambi ku ri byalwa, wena ni vana va wena, loko mi nghena etabernakela ya nhlanganiso, leswaku mi nga fi; i nawu wa vutomi lebyi nga heriki eka tinxaka ta n’wina.”' },
    { n: 10, text: '“Leswaku mi hambanisa leswo kwetsima ni leswo nyamisa, ni leswo tenga ni leswo nga tengangiki.”' },
    { n: 11, text: '“Ni leswaku mi dyondzisa vana va Israyele swileriso hinkwaswo leswi Yehovha a va byeleke hi Moxe.”' },
    { n: 12, text: '“Moxe a ku eka Aroni ni vana va yena lava saleke, Eleazara ni Itamara: Tekani munyikelo wa xinkwa lowu saleke eka minyikelo ya ndzilo ya Yehovha, mi wu dya wu nga riki na comela, mi wu dyela etlhelweni ra alitari, hikuva i xo kwetsima swinene.”' },
    { n: 13, text: '“Mi ta wu dya endhawini yo kwetsima, hikuva i xiphemu xa n’wina ni xiphemu xa vana va n’wina eka minyikelo ya ndzilo ya Yehovha; hikuva hi swona leswi ndzi lerisiweke hakona.”' },
    { n: 14, text: '“Ni xipeni xa munyikelo, ni nenge wa munyikelo, mi ta wu dyela endhawini yo tenga, wena ni vana va wena ni vana va vana va wena; hikuva i xiphemu xa n’wina ni xiphemu xa vana va n’wina, lexi xi nyikiweke eka switlhavelo swa ku rhula swa vana va Israyele.”' },
    { n: 15, text: '“Nenge wa munyikelo ni xipeni xa munyikelo va ta wu tisa swi ri na mafurha ya minyikelo ya ndzilo, leswaku xi nyikelwa mahlweni ka Yehovha; xi ta va xa wena ni xa vana va wena, i nawu wa vutomi lebyi nga heriki, hilaha Yehovha a leriseke hakona.”' },
    { n: 16, text: '“Moxe a lava mpongo wa xidyoho, naswona wu hisiwile; a a hlundzukela Eleazara ni Itamara, vana va Aroni lava saleke, a ku:”' },
    { n: 17, text: '“Hikwalaho ka yini mi nga dyanga xidyoho endhawini yo kwetsima? Hikuva i xo kwetsima swinene, naswona xi mi nyikile leswaku mi rhwala nandzu wa nhlengeletano, mi va endlela mukutsulo mahlweni ka Yehovha.”' },
    { n: 18, text: '“Langutani, ngati ya xona a yi nghenisiwanga endhawini yo kwetsima; mi fanele mi xi dyile endhawini yo kwetsima, hilaha ndzi leriseke hakona.”' },
    { n: 19, text: '“Aroni a ku eka Moxe: Languta, namuntlha va tise xidyoho xa vona ni xitlhavelo xo hisiwa mahlweni ka Yehovha, naswona swilo leswi swi ndzi humelele; loko ndzi dya xidyoho namuntlha, xi nga amukeleka mahlweni ka Yehovha?”' },
    { n: 20, text: '“Moxe a twa leswi, naswona swi n’wi tsakisa.”' }
  ],
  11: [
    { n: 1, text: 'Yehovha a vulavula na Moxe na Aroni, a ku eka vona:' },
    { n: 2, text: '“Vulavulani ni vana va Israyele, mi ku eka vona: Leswi i swivandzana leswi mi nga ta swi dya exikarhi ka swifuwo hinkwaswo leswi nga emisaveni.”' },
    { n: 3, text: '“Hinkwaswo leswi nga ni xihontlovu, leswi hlantlaka xihontlovu, leswi nga swifuwo, sweswo mi ta swi dya.”' },
    { n: 4, text: '“Kambe eka leswi hlantlaka xihontlovu, ni leswi nga ni mikondzo leyi hambaneke, mi nga swi dyi: Kamela, hikuva hambi yi hlantla xihontlovu, kambe a yi na mikondzo leyi hambaneke, yi nga tengangiki eka n’wina.”' },
    { n: 5, text: '“Ni xikwarati, hikuva hambi xi hlantla xihontlovu, kambe a xi na mikondzo leyi hambaneke, xi nga tengangiki eka n’wina.”' },
    { n: 6, text: '“Ni mpfundla, hikuva hambi wu hlantla xihontlovu, kambe a wu na mikondzo leyi hambaneke, wu nga tengangiki eka n’wina.”' },
    { n: 7, text: '“Ni nguluve, hikuva hambi yi na mikondzo leyi hambaneke, kambe a yi hlantli xihontlovu, yi nga tengangiki eka n’wina.”' },
    { n: 8, text: '“Nyama ya sweswo mi nga yi dyi, ni mintsumbu ya swona mi nga yi khumbi; swi nga tengangiki eka n’wina.”' },
    { n: 9, text: '“Leswi mi nga ta swi dya exikarhi ka hinkwaswo leswi nga ematini: Hinkwaswo leswi nga ni tiphiko ni swikalo ematini, erilwandle ni le milambyeni, sweswo mi ta swi dya.”' },
    { n: 10, text: '“Kambe hinkwaswo leswi nga riki na tiphiko ni swikalo, erilwandle ni le milambyeni, hinkwaswo leswi tsutsumaka ematini, ni hinkwaswo leswi hanyaka ematini, swi nga nchumu lowu nyamisaka eka n’wina.”' },
    { n: 11, text: '“Swi ta va nchumu lowu nyamisaka eka n’wina; mi nga dyi nyama ya swona, ni mintsumbu ya swona mi ta yi languta tanihi nchumu lowu nyamisaka.”' },
    { n: 12, text: '“Hinkwaswo leswi nga riki na tiphiko ni swikalo ematini, swi nga nchumu lowu nyamisaka eka n’wina.”' },
    { n: 13, text: '“Leswi mi nga ta swi nyenyela exikarhi ka tinyenyana, swi nga dyiwi, swi nyenyisa: Gowa, ni xikhozi, ni xikhozi xa le mahlweni.”' },
    { n: 14, text: '“Ni xikhozi xa le ndzhaku, ni xikhozi xa mixaka hinkwayo.”' },
    { n: 15, text: '“Ni mpfundla wa mixaka hinkwayo.”' },
    { n: 16, text: '“Ni xikhozi xa le matini, ni xikhozi xa le ribyeni, ni xikhozi xa mixaka hinkwayo.”' },
    { n: 17, text: '“Ni xikhozi xa le tihun’wini, ni xikhozi xa le matini, ni xikhozi xa mixaka hinkwayo.”' },
    { n: 18, text: '“Ni xikhozi xa le ndhawini yo hisa, ni xikhozi xa le matini, ni xikhozi xa le ribyeni.”' },
    { n: 19, text: '“Ni xikhozi xa mixaka hinkwayo, ni xikhozi xa le matini, ni xikhozi xa mixaka hinkwayo.”' },
    { n: 20, text: '“Switsotswana hinkwaswo leswi hahaka, leswi fambaka hi milenge mune, swi nga nchumu lowu nyamisaka eka n’wina.”' },
    { n: 21, text: '“Kambe switsotswana leswi hahaka, leswi fambaka hi milenge mune, leswi nga ni milenge yo tlula ha yona, swi nga switsotswana leswi mi nga ta swi dya.”' },
    { n: 22, text: '“Leswi mi nga ta swi dya: Tinhongana ta mixaka hinkwayo, ni tihongana ta mixaka hinkwayo, ni tihongana ta mixaka hinkwayo.”' },
    { n: 23, text: '“Kambe switsotswana hinkwaswo leswi hahaka, leswi nga ni milenge ya mune, swi nga nchumu lowu nyamisaka eka n’wina.”' },
    { n: 24, text: '“Hi swona leswi swi nga ta mi nyamisa; un’wana ni un’wana la khumbaka ntsumbu wa swona, u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 25, text: '“Naswona un’wana ni un’wana la rhwalaka ntsumbu wa swona, u ta hlantswa tinguvu ta yena, u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 26, text: '“Swifuwo hinkwaswo leswi nga riki na mikondzo leyi hambaneke, kumbe leswi nga hlantliki xihontlovu, swi nga nchumu lowu nyamisaka eka n’wina; un’wana ni un’wana la swi khumbaka u ta va ni nandzu.”' },
    { n: 27, text: '“Hinkwaswo leswi fambaka hi milenge, exikarhi ka swivandzana swa mune, swi nga nchumu lowu nyamisaka eka n’wina; un’wana ni un’wana la khumbaka ntsumbu wa swona u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 28, text: '“La rhwalaka ntsumbu wa swona u ta hlantswa tinguvu ta yena, u ta va ni nandzu ku fikela nimadyambu; swi nga nchumu lowu nyamisaka eka n’wina.”' },
    { n: 29, text: '“Ni leswi swi nga switsotswana leswi hohlovaka emisaveni: Xikwambana, ni mpfundla, ni n’wina wa mixaka hinkwayo.”' },
    { n: 30, text: '“Ni xikwambana, ni xikwambana, ni xikwambana, ni xikwambana.”' },
    { n: 31, text: '“Sweswi swi nga nchumu lowu nyamisaka eka n’wina; un’wana ni un’wana la swi khumbaka loko swi file, u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 32, text: '“Naswona hinkwaswo leswi swi wela eka swona loko swi file, swi ta va nchumu lowu nyamisaka: Xibya xa mhandzi, kumbe tinguvu, kumbe dzovo, kumbe xikhwama, xibya xin’wana ni xin’wana lexi tirhisiwaka, xi ta hoxiwa ematini, xi ta va ni nandzu ku fikela nimadyambu, xi ta va xi tenge.”' },
    { n: 33, text: '“Xibya xin’wana ni xin’wana xa vumba lexi swi welaka eka xona, hinkwaswo leswi nga endzeni swi ta va nchumu lowu nyamisaka, mi ta xi tshova.”' },
    { n: 34, text: '“Swakudya hinkwaswo leswi nga dyiwa, leswi mati ma nga wela eka swona, swi ta va nchumu lowu nyamisaka; ni byalwa hinkwabyo lebyi nga endzeni, xi ta va nchumu lowu nyamisaka.”' },
    { n: 35, text: '“Hinkwaswo leswi ntsumbu wa swona wu welaka eka swona, swi ta va nchumu lowu nyamisaka; alitari kumbe swibye swa mati swi ta tshoviwa; swi nga nchumu lowu nyamisaka, swi ta va nchumu lowu nyamisaka eka n’wina.”' },
    { n: 36, text: '“Kambe xihlovo kumbe xidziva lexi nga ni mati xi ta va xi tenge; kambe la khumbaka ntsumbu wa swona u ta va ni nandzu.”' },
    { n: 37, text: '“Loko ntsumbu wa swona wu wela eka mbewu leyi byariwaka, yi ta va yi tenge.”' },
    { n: 38, text: '“Kambe loko mati ma cheliwile eka mbewu, naswona ntsumbu wa swona wu wela eka yona, swi ta va nchumu lowu nyamisaka eka n’wina.”' },
    { n: 39, text: '“Loko xi fela eka swifuwo leswi mi nga ta swi dya, la khumbaka ntsumbu wa swona u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 40, text: '“La dyaka ntsumbu wa swona u ta hlantswa tinguvu ta yena, u ta va ni nandzu ku fikela nimadyambu; la rhwalaka ntsumbu wa swona u ta hlantswa tinguvu ta yena, u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 41, text: '“Switsotswana hinkwaswo leswi hohlovaka emisaveni swi nga nchumu lowu nyamisaka, swi nga dyiwi.”' },
    { n: 42, text: '“Hinkwaswo leswi fambaka hi khwiri, ni hinkwaswo leswi fambaka hi milenge mune, ni hinkwaswo leswi nga ni milenge yo tala, exikarhi ka switsotswana hinkwaswo leswi hohlovaka emisaveni, mi nga swi dyi, hikuva swi nga nchumu lowu nyamisaka.”' },
    { n: 43, text: '“Mi nga tiyendli swi nga tengangiki hi switsotswana hinkwaswo leswi hohlovaka, mi nga tiyendli swi nga tengangiki ha swona, leswaku mi nga va ni nandzu.”' },
    { n: 44, text: '“Hikuva hi mina Yehovha Xikwembu xa n’wina; mi ta tiyendla mi kwetsima, hikuva ndza kwetsima; mi nga tiyendli swi nga tengangiki hi switsotswana hinkwaswo leswi hohlovaka emisaveni.”' },
    { n: 45, text: '“Hikuva hi mina Yehovha, loyi a mi humeseke etikweni ra Egipta, leswaku ndzi va Xikwembu xa n’wina; mi ta va vakwetsimi, hikuva ndza kwetsima.”' },
    { n: 46, text: '“Lowu i nawu wa swifuwo, ni tinyenyana, ni hinkwaswo leswi hanyaka ematini, ni hinkwaswo leswi hohlovaka emisaveni.”' },
    { n: 47, text: '“Leswaku mi hambanisa leswo nyamisa ni leswo tenga, ni leswi nga dyiwaka ni leswi nga dyiwiki.”' }
  ],
  12: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku: Loko wansati a tswala n’wana wa xinuna, u ta va ni nandzu masiku ya nhungu; tanihi masiku ya ku nyamisa ka yona, u ta va ni nandzu.”' },
    { n: 3, text: '“Hi siku ra vunhungu, xihontlovu xa n’wana xi ta tsemiwa.”' },
    { n: 4, text: '“U ta tshama masiku ya 33 hi ngati ya ku tenga ka yena; u ta nga khumbi nchumu wo kwetsima, a a nga ngheni endlwini ya ku kwetsima, ku fikela loko masiku ya ku tenga ka yena ma herile.”' },
    { n: 5, text: '“Loko a tswala n’wana wa xisati, u ta va ni nandzu masiku ya 14, tanihi ku nyamisa ka yona; u ta tshama masiku ya 66 hi ngati ya ku tenga ka yena.”' },
    { n: 6, text: '“Loko masiku ya ku tenga ka yena ma herile, hikwalaho ka n’wana wa xinuna kumbe wa xisati, a a tise xinyimpfu xa lembe rin’we xa xitlhavelo xo hisiwa, ni xinyimpfu kumbe xihontlovu xa xidyoho, emunyangweni wa tabernakela ya nhlanganiso, eka muprista.”' },
    { n: 7, text: '“A a swi nyikela mahlweni ka Yehovha, muprista a a yi endlele mukutsulo, yi ta tenga eka ku huma ka ngati ya yona; lowu i nawu wa loyi a tswaleke n’wana wa xinuna kumbe wa xisati.”' },
    { n: 8, text: '“Loko a nga ri na mali ya xinyimpfu, a a teke tinyenyana timbirhi, tinjiwa kumbe swiwa-tiva, xin’we xa xitlhavelo xo hisiwa, ni xin’we xa xidyoho; muprista a a yi endlele mukutsulo, yi ta tenga.”' }
  ],
  13: [
    { n: 1, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 2, text: '“Loko munhu a va ni xiviti elangeni ra miri wa yena, kumbe xilondzo, kumbe xitshwatslwa, naswona xi va xiviti elangeni ra miri wa yena, a a tisiwe eka muprista Aroni, kumbe eka un’wana wa vana va yena, vaprista.”' },
    { n: 3, text: '“Muprista a a langute xiviti elangeni ra miri; loko ntimu wa xiviti wu hundzukile wu va wa tshese, naswona xiviti xi ri ku anameni ku tlula ntlawa wa miri wa yena, i xiviti xa nchumu lowu nyamisaka; muprista a a xi langute, a a ku xi nga tenga.”' },
    { n: 4, text: '“Loko ntimu wa tshese wu ri wa mpupuri elangeni ra miri, naswona a xi aname ku tlula ntlawa, ni ntimu wa xona wu nga hundzukanga wu va wa tshese, muprista a a pfalele munhu loyi a nga ni xiviti masiku ya nhungu.”' },
    { n: 5, text: '“Muprista a a xi langute hi siku ra vunhungu; loko xiviti xi tshamile hi ndlela ya xona, naswona xi nga anamananga elangeni, muprista a a pfalele yena masiku man’wana ya nhungu.”' },
    { n: 6, text: '“Muprista a a xi langute hi siku ra vunharhu, naswona xiviti xi xile, naswona xi nga anamananga elangeni, muprista a a ku xi nga tenga; i xitshwatslwa ntsena; u ta hlantswa tinguvu ta yena, a a tenga.”' },
    { n: 7, text: '“Kambe loko xitshwatslwa xi anama ngopfu elangeni, endzhaku ka loko a humelele eka muprista leswaku a tenga, a a humelele eka muprista ra vumbirhi.”' },
    { n: 8, text: '“Muprista a a xi langute, naswona loko xitshwatslwa xi anama elangeni, muprista a a ku xi nga tenga; i xiviti.”' },
    { n: 9, text: '“Loko xiviti xi ri eka munhu, a a tisiwe eka muprista.”' },
    { n: 10, text: '“Muprista a a xi langute, naswona loko ntimu wa tshese wu ri elangeni, naswona wu hundzule xiviti xi va wa tshese, naswona ku ri ni swirho swa nyama leyi hanyaka elangeni;”' },
    { n: 11, text: '“I xiviti xa khale elangeni ra miri wa yena, muprista a a ku xi nga tenga, a nga pfumeli ku xi pfalela, hikuva xi nga nchumu lowu nyamisaka.”' },
    { n: 12, text: '“Loko xiviti xi anama hinkwako elangeni, naswona xi funengeta miri hinkwawo wa xiviti, kusukela enhlokweni ku ya emilenjeni, laha muprista a langutaka kona;”' },
    { n: 13, text: '“Muprista a a langute, naswona loko xiviti xi funengete miri hinkwawo, a a ku xi nga tenga; hinkwaswo swi hundzukile swi va swa tshese, xi nga tenga.”' },
    { n: 14, text: '“Kambe hi siku leri nyama leyi hanyaka yi humelelaka eka xona, xi ta va xi nga tenga.”' },
    { n: 15, text: '“Muprista a a langute nyama leyi hanyaka, a a ku xi nga tenga; nyama leyi hanyaka yi nga nchumu lowu nyamisaka, i xiviti.”' },
    { n: 16, text: '“Loko nyama leyi hanyaka yi hundzuka, yi hundzuka yi va ya tshese, a a te eka muprista.”' },
    { n: 17, text: '“Muprista a a xi langute, naswona loko xiviti xi hundzukile xi va xa tshese, muprista a a ku xi nga tenga; xi nga tenga.”' },
    { n: 18, text: '“Loko munhu a va ni xilondzo elangeni ra miri wa yena, naswona xi tshwile;”' },
    { n: 19, text: '“Naswona exikarhi ka xilondzo ku ri ni ntimu wa tshese, kumbe xitshwatslwa xa tshese, a a humelele eka muprista.”' },
    { n: 20, text: '“Muprista a a xi langute, naswona loko xi anama ku tlula ntlawa, naswona ntimu wa xona wu hundzukile wu va wa tshese, muprista a a ku xi nga tenga; i xiviti xa xilondzo.”' },
    { n: 21, text: '“Kambe loko muprista a xi languta, naswona ntimu wa xona wu nga ri wa tshese, naswona xi nga anamananga, kambe xi ri xo tsetselela, muprista a a pfalele yena masiku ya nhungu.”' },
    { n: 22, text: '“Loko xi anama ngopfu elangeni, muprista a a ku xi nga tenga; i xiviti.”' },
    { n: 23, text: '“Kambe loko xitshwatslwa xi tshamile hi ndlela ya xona, naswona xi nga anamananga, i xilondzo xa ku tsha, muprista a a ku xi nga tenga.”' },
    { n: 24, text: '“Loko munhu a va ni ndzilo elangeni, naswona xitshwatslwa xa ndzilo xi va ni ntimu wa tshese kumbe wa tshese,”' },
    { n: 25, text: '“Muprista a a xi langute, naswona loko ntimu wa xitshwatslwa wu hundzukile wu va wa tshese, naswona xi anama elangeni, i xiviti xa ndzilo, muprista a a ku xi nga tenga.”' },
    { n: 26, text: '“Kambe loko muprista a xi languta, naswona ntimu wa xitshwatslwa wu nga ri wa tshese, naswona xi nga anamananga, kambe xi ri xo tsetselela, muprista a a pfalele yena masiku ya nhungu.”' },
    { n: 27, text: '“Muprista a a xi langute hi siku ra vunhungu, naswona loko xi anama ngopfu elangeni, muprista a a ku xi nga tenga; i xiviti.”' },
    { n: 28, text: '“Kambe loko xitshwatslwa xi tshamile hi ndlela ya xona, naswona xi nga anamananga elangeni, kambe xi ri xo tsetselela, i xitshwatslwa xa ndzilo, muprista a a ku xi nga tenga.”' },
    { n: 29, text: '“Loko wanuna kumbe wansati a va ni xiviti enhlokweni kumbe erivaleni;”' },
    { n: 30, text: '“Muprista a a langute xiviti, naswona loko xi anama ku tlula ntlawa, naswona ku ri ni swirho swa tshese leswi nga riki na matluka, muprista a a ku xi nga tenga; i xiviti xa nhloko.”' },
    { n: 31, text: '“Loko muprista a languta xiviti, naswona xi nga anamananga ku tlula ntlawa, naswona ku nga riki na tshese, muprista a a pfalele munhu loyi a nga ni xiviti masiku ya nhungu.”' },
    { n: 32, text: '“Muprista a a xi langute hi siku ra vunhungu, naswona loko xiviti xi nga anamananga, naswona ku nga riki na tshese, naswona xi nga anamananga elangeni;”' },
    { n: 33, text: '“A a tiveka, kambe a nga tiveki laha ku nga na tshese; muprista a a pfalele munhu loyi a nga ni xiviti masiku man’wana ya nhungu.”' },
    { n: 34, text: '“Muprista a a xi langute hi siku ra vunhungu, naswona loko xiviti xi nga anamananga elangeni, naswona xi nga ri xa tshese, muprista a a ku xi nga tenga; u ta hlantswa tinguvu ta yena, a a tenga.”' },
    { n: 35, text: '“Kambe loko xiviti xi anama elangeni endzhaku ka ku tenga ka yena;”' },
    { n: 36, text: '“Muprista a a xi langute, naswona loko xiviti xi anama elangeni, muprista a nga ha languti tshese, xi nga tenga.”' },
    { n: 37, text: '“Kambe loko xiviti xi tshamile hi ndlela ya xona, naswona tshese yi humelele, xiviti xi hanyile, xi nga tenga, muprista a a ku xi nga tenga.”' },
    { n: 38, text: '“Loko wanuna kumbe wansati a va ni swirho elangeni ra miri wa yena, swirho swa tshese;”' },
    { n: 39, text: '“Muprista a a xi langute, naswona loko swirho swi ri swa tshese elangeni ra miri wa yena, i xiviti xa xirho lexi humeleleke elangeni; xi nga tenga.”' },
    { n: 40, text: '“Loko munhu a lahlekeriwa hi miri wa yena, i xiviti xa nhloko; xi nga tenga.”' },
    { n: 41, text: '“Loko a lahlekeriwa hi miri wa yena enhlokweni, i xiviti xa nhloko; xi nga tenga.”' },
    { n: 42, text: '“Kambe loko xi ri ni xiviti xa tshese elangeni, enhlokweni, kumbe erivaleni, i xiviti lexi humeleleke elangeni.”' },
    { n: 43, text: '“Muprista a a xi langute, naswona loko xiviti xi ri xa tshese elangeni ra miri wa yena, i xiviti lexi humeleleke elangeni;”' },
    { n: 44, text: '“I munhu loyi a nga ni xiviti, xi nga tenga; muprista a a ku xi nga tenga; i xiviti enhlokweni ya yena.”' },
    { n: 45, text: '“Loyi a nga ni xiviti, a a ambalise tinguvu, a a ambarise nhloko ya yena, a a tsheme matluka ya yena, a a huwelela a ku: Nchumu lowu nyamisaka, nchumu lowu nyamisaka!”' },
    { n: 46, text: '“Masiku hinkwato lawa xiviti xi nga eka yena, u ta va ni nandzu; u nga tenga, u ta tshama ehandle ka nkambi.”' },
    { n: 47, text: '“Loko tinguvu ti ri ni xiviti, tinguvu ta wulu kumbe ta ntsembe;”' },
    { n: 48, text: '“Kumbe eka ntsembe, kumbe eka wulu, kumbe eka dzovo, kumbe eka nchumu wa dzovo;”' },
    { n: 49, text: '“Naswona xiviti xi ri xa tshese kumbe xa tshese eka tinguvu, kumbe eka dzovo, kumbe eka ntsembe, kumbe eka wulu, kumbe eka nchumu wa dzovo, i xiviti xa nchumu lowu nyamisaka, xi ta kombiwa muprista.”' },
    { n: 50, text: '“Muprista a a xi langute, a a pfalele nchumu lowu nga ni xiviti masiku ya nhungu.”' },
    { n: 51, text: '“A a xi langute hi siku ra vunhungu, naswona loko xiviti xi anama eka tinguvu, kumbe eka ntsembe, kumbe eka wulu, kumbe eka dzovo, i xiviti xa nchumu lowu nyamisaka, xi nga tenga.”' },
    { n: 52, text: '“A a hise tinguvu, kumbe wulu kumbe ntsembe, eka tinguvu, eka nchumu wa dzovo, hikuva i xiviti xa nchumu lowu nyamisaka, xi ta hisiwa hi ndzilo.”' },
    { n: 53, text: '“Loko muprista a xi languta, naswona loko xiviti xi nga anamananga eka tinguvu, kumbe eka wulu, kumbe eka ntsembe, kumbe eka nchumu wa dzovo;”' },
    { n: 54, text: '“Muprista a a lerise leswaku va hlantswa nchumu lowu nga ni xiviti, a a pfalele wona masiku man’wana ya nhungu.”' },
    { n: 55, text: '“Muprista a a xi langute endzhaku ka loko xi hlantswiwile, naswona loko xiviti xi nga hundzukanga, naswona xi nga anamananga, xi nga tenga; u ta xi hisa hi ndzilo; i xiviti, kumbe xi ri endzeni kumbe ehandle.”' },
    { n: 56, text: '“Loko muprista a xi languta, naswona loko xiviti xi ri xo tsetselela endzhaku ka ku hlantswiwa ka xona, a a xi tsema eka tinguvu, kumbe eka dzovo, kumbe eka wulu, kumbe eka ntsembe.”' },
    { n: 57, text: '“Loko xi humelela ra vumbirhi eka tinguvu, kumbe eka wulu, kumbe eka ntsembe, kumbe eka nchumu wa dzovo, xi anama ngopfu; u ta hisa nchumu lowu nga ni xiviti hi ndzilo.”' },
    { n: 58, text: '“Tinguvu, kumbe wulu, kumbe ntsembe, kumbe nchumu wa dzovo, lowu u wu hlantsweke, loko xiviti xi sukerile, xi ta hlantswiwa ra vumbirhi, xi ta tenga.”' },
    { n: 59, text: '“Lowu i nawu wa xiviti xa tinguvu ta wulu kumbe ta ntsembe, eka tinguvu, kumbe eka dzovo, kumbe eka nchumu wa dzovo, ku ku xi nga tenga kumbe xi tenga.”' }
  ],
  14: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Lowu i nawu wa munhu loyi a nga ni xiviti hi siku ra ku tenga ka yena; a a tisiwe eka muprista.”' },
    { n: 3, text: '“Muprista a a humelele ehandle ka nkambi, a a langute, naswona loko xiviti xi hanyile eka munhu loyi a nga ni xiviti;”' },
    { n: 4, text: '“Muprista a a lerise leswaku va teka tinyenyana timbirhi leti hanyaka ni leti tengeke, ni matluka ya sidara, ni xilapi xa xitswaka, ni hisopo.”' },
    { n: 5, text: '“Muprista a a lerise leswaku va tlhave nyenyana yin’we ehenhla ka xibya xa mati lama humaka etshurini.”' },
    { n: 6, text: '“Nyenyana leyi hanyaka, a a yi teke, ni matluka ya sidara, ni xilapi xa xitswaka, ni hisopo, a a swi mbita hi ngati ya nyenyana leyi tlhaviweke ehenhla ka mati lama humaka etshurini.”' },
    { n: 7, text: '“A a fafata loyi a nga ni xiviti makhamba ya nhungu, a a ku xi nga tenga, a a tshika nyenyana leyi hanyaka yi haha emadyambyeni.”' },
    { n: 8, text: '“Loyi a nga ni xiviti a a hlantswa tinguvu ta yena, a a tsema matluka ya yena hinkwawo, a a hlantswa hi mati, a a tenga; endzhaku ka sweswo a a nghena enkambini, kambe a a tshama ehandle ka tabernakela ya yena masiku ya nhungu.”' },
    { n: 9, text: '“Hi siku ra vunhungu, a a tsema matluka ya yena hinkwawo, enhlokweni, ni le mahlweni, ni le ku heteleleni ka yena; a a hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a tenga.”' },
    { n: 10, text: '“Hi siku ra vunhungu, a a teke swinyimpfu swimbirhi leswi nga riki na xilaveko, ni xinyimpfu xin’we xa lembe rin’we xa xidyoho, ni swiphemu swinharhu swa mapa lamamanene, ni mafurha, tanihi munyikelo wa xinkwa.”' },
    { n: 11, text: '“Muprista la tengisaka a a tise munhu loyi a tenga, ni leswi, mahlweni ka Yehovha, emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 12, text: '“Muprista a a teke xinyimpfu xin’we, a a xi nyikela tanihi munyikelo wa nandzu, ni mafurha, a a swi nyikela tanihi munyikelo mahlweni ka Yehovha.”' },
    { n: 13, text: '“A a tlhave xinyimpfu laha ku tlhaviwaka xidyoho ni xitlhavelo xo hisiwa, endhawini yo kwetsima; hikuva tanihi xidyoho xi nga xa muprista, tanihi munyikelo wa nandzu, i xo kwetsima swinene.”' },
    { n: 14, text: '“Muprista a a teke ngati ya munyikelo wa nandzu, a a chela etimponjini ta tindleve ta munhu loyi a tenga, ni le vukolweni bya voko ra yena ra xinene, ni le xipeni xa nenge wa yena wa xinene.”' },
    { n: 15, text: '“Muprista a a teke mafurha, a a chela evukolweni bya voko ra yena ra xinene;”' },
    { n: 16, text: '“Muprista a a mbita munwe wa yena hi mafurha lama nga evukolweni bya voko ra yena ra xinene, a a fafata mafurha makhamba ya nhungu mahlweni ka Yehovha.”' },
    { n: 17, text: '“Muprista a a chela mafurha lama saleke evukolweni bya voko ra yena ra xinene, etimponjini ta tindleve ta munhu loyi a tenga, ni le vukolweni bya voko ra yena ra xinene, ni le xipeni xa nenge wa yena wa xinene, ehenhla ka ngati ya munyikelo wa nandzu.”' },
    { n: 18, text: '“Lama saleke evukolweni bya muprista a a ma chela enhlokweni ya munhu loyi a tenga; muprista a a yi endlele mukutsulo mahlweni ka Yehovha.”' },
    { n: 19, text: '“Muprista a a nyikela xidyoho, a a endla mukutsulo wa loyi a nga ni xiviti hi ku tenga ka yena; endzhaku ka sweswo a a tlhave xitlhavelo xo hisiwa.”' },
    { n: 20, text: '“Muprista a a nyikela xitlhavelo xo hisiwa ealitari, ni munyikelo wa xinkwa; muprista a a yi endlele mukutsulo, a a tenga.”' },
    { n: 21, text: '“Loko a ri xisiwana, naswona a nga ri na mali, a a teke xinyimpfu xin’we tanihi munyikelo wa nandzu, ni xiphemu xin’we xa mapa lamamanene, ni mafurha, tanihi munyikelo wa xinkwa, ni xipeni xa mafurha.”' },
    { n: 22, text: '“Ni tinyenyana timbirhi, tinjiwa kumbe swiwa-tiva, hi laha a nga na hakona; xin’we xa xidyoho, ni xin’we xa xitlhavelo xo hisiwa.”' },
    { n: 23, text: '“A a swi tise hi siku ra vunhungu eka muprista, emunyangweni wa tabernakela ya nhlanganiso, mahlweni ka Yehovha.”' },
    { n: 24, text: '“Muprista a a teke xinyimpfu xa munyikelo wa nandzu, ni xipeni xa mafurha, muprista a a swi nyikela tanihi munyikelo mahlweni ka Yehovha.”' },
    { n: 25, text: '“A a tlhave xinyimpfu xa munyikelo wa nandzu, muprista a a teke ngati ya munyikelo wa nandzu, a a chela etimponjini ta tindleve ta munhu loyi a tenga, ni le vukolweni bya voko ra yena ra xinene, ni le xipeni xa nenge wa yena wa xinene.”' },
    { n: 26, text: '“Muprista a a chela mafurha evukolweni bya voko ra yena ra xinene;”' },
    { n: 27, text: '“Muprista a a mbita munwe wa yena hi mafurha lama nga evukolweni bya voko ra yena ra xinene, a a fafata makhamba ya nhungu mahlweni ka Yehovha.”' },
    { n: 28, text: '“Muprista a a chela mafurha evukolweni bya voko ra yena ra xinene, etimponjini ta tindleve ta munhu loyi a tenga, ni le vukolweni bya voko ra yena ra xinene, ni le xipeni xa nenge wa yena wa xinene, ehenhla ka ngati ya munyikelo wa nandzu.”' },
    { n: 29, text: '“Lama saleke evukolweni bya muprista a a ma chela enhlokweni ya munhu loyi a tenga, a a yi endlele mukutsulo mahlweni ka Yehovha.”' },
    { n: 30, text: '“A a nyikela xin’we xa tinjiwa kumbe swiwa-tiva, hi laha a nga na hakona;”' },
    { n: 31, text: '“Xin’we xa xidyoho, ni xin’we xa xitlhavelo xo hisiwa, ni munyikelo wa xinkwa; muprista a a yi endlele mukutsulo mahlweni ka Yehovha.”' },
    { n: 32, text: '“Lowu i nawu wa loyi a nga ni xiviti, loyi a nga riki na mali yo tenga.”' },
    { n: 33, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 34, text: '“Loko mi nghena etikweni ra Kanana, leri ndzi mi nyikaka rona tanihi ndzhaka, naswona ndzi veka xiviti xa nchumu lowu nyamisaka endlwini ya tiko ra ndzhaka ya n’wina;”' },
    { n: 35, text: '“N’wini wa yindlu a a tise, a a byela muprista, a ku: Ndzi vona nchumu lowu nyamisaka endlwini ya mina.”' },
    { n: 36, text: '“Muprista a a lerise leswaku va hluvula yindlu, loko a nga si nghena leswaku a languta nchumu lowu nyamisaka, leswaku hinkwaswo leswi nga endlwini swi nga va nchumu lowu nyamisaka; endzhaku ka sweswo muprista a a nghena leswaku a languta yindlu.”' },
    { n: 37, text: '“A a langute nchumu lowu nyamisaka, naswona loko xiviti xi ri ni swirho swa tshese kumbe swa tshese elangeni ra yindlu, naswona xi anama elangeni;”' },
    { n: 38, text: '“Muprista a a huma endlwini ya yindlu, a a pfalele yindlu masiku ya nhungu.”' },
    { n: 39, text: '“Muprista a a tlhelela hi siku ra vunhungu, a a langute; naswona loko xiviti xi anama elangeni ra yindlu;”' },
    { n: 40, text: '“Muprista a a lerise leswaku va hluvula maribye lawa ma nga na nchumu lowu nyamisaka, va ma cukumeta ehandle ka muti endhawini leyi nga tengangiki.”' },
    { n: 41, text: '“A a lerise leswaku va tsetselela yindlu hinkwayo, va cukumeta nkuma lowu va wu hluvuleke ehandle ka muti endhawini leyi nga tengangiki.”' },
    { n: 42, text: '“Va teka maribye man’wana, va ma veka ematshan’wini ya maribye, va teka ntsembe wun’wana, va tsetselela yindlu.”' },
    { n: 43, text: '“Loko xiviti xi tlhelela xi humelela endlwini, endzhaku ka loko va hluvule maribye, naswona va tsetselele yindlu;”' },
    { n: 44, text: '“Muprista a a nghena, a a langute; naswona loko xiviti xi anama endlwini, i xiviti xa khale endlwini; xi nga nchumu lowu nyamisaka.”' },
    { n: 45, text: '“A a tshova yindlu, maribye ya yona, ni tihunyi ta yona, ni ntsembe hinkwawo wa yindlu; a a swi humesa ehandle ka muti endhawini leyi nga tengangiki.”' },
    { n: 46, text: '“La nghenaka endlwini masiku hinkwato lawa yi pfariweke, u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 47, text: '“La etlelaka endlwini, u ta hlantswa tinguvu ta yena; la dyaka endlwini, u ta hlantswa tinguvu ta yena.”' },
    { n: 48, text: '“Loko muprista a nghena, a a languta, naswona loko xiviti xi nga anamananga endlwini, endzhaku ka ku tsetselela ka yindlu, muprista a a ku yindlu yi nga tenga, hikuva xiviti xi sukerile.”' },
    { n: 49, text: '“A a teke tinyenyana timbirhi, ni matluka ya sidara, ni xilapi xa xitswaka, ni hisopo, leswaku a tengisa yindlu.”' },
    { n: 50, text: '“A a tlhave nyenyana yin’we ehenhla ka xibya xa mati lama humaka etshurini.”' },
    { n: 51, text: '“A a teke matluka ya sidara, ni hisopo, ni xilapi xa xitswaka, ni nyenyana leyi hanyaka, a a mbita hi ngati ya nyenyana leyi tlhaviweke ni mati lama humaka etshurini, a a fafata yindlu makhamba ya nhungu.”' },
    { n: 52, text: '“A a tengisa yindlu hi ngati ya nyenyana, ni hi mati lama humaka etshurini, ni hi nyenyana leyi hanyaka, ni hi matluka ya sidara, ni hi hisopo, ni hi xilapi xa xitswaka.”' },
    { n: 53, text: '“A a tshika nyenyana leyi hanyaka yi haha emadyambyeni ehandle ka muti; a a yi endlele mukutsulo yindlu, yi ta tenga.”' },
    { n: 54, text: '“Lowu i nawu wa xiviti hinkwaxo, ni xitshwatslwa,”' },
    { n: 55, text: '“Ni xiviti xa tinguvu, ni xa yindlu,”' },
    { n: 56, text: '“Ni xirho, ni xiviti, ni ntimu,”' },
    { n: 57, text: '“Leswaku mi hambanisa leswaku nchumu hi wunhi lowu nyamisaka ni nchumu hi wunhi lowu tengaka; lowu i nawu wa xiviti.”' }
  ],
  15: [
    { n: 1, text: 'Yehovha a vulavula na Moxe na Aroni, a ku eka vona:' },
    { n: 2, text: '“Vulavulani ni vana va Israyele, mi ku eka vona: Un’wana ni un’wana loyi a nga ni ku huma ka mati enhlolelo ya miri wa yena, i munhu la nga tengangiki.”' },
    { n: 3, text: '“Leswi i ku nyamisa ka yena hikwalaho ka ku huma ka miri wa yena; hambi ku huma mati kumbe ku pfaleka ka miri, i ku nyamisa ka yena.”' },
    { n: 4, text: '“Mubedo hinkwawo lowu a etlelaka eka wona la nga ni ku huma ka miri, wu ta va nchumu lowu nyamisaka; ni swilo hinkwaswo leswi a tshamaka eka swona swi ta va nchumu lowu nyamisaka.”' },
    { n: 5, text: '“Un’wana ni un’wana la khumbaka mubedo wa yena u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 6, text: '“La tshamaka laha munhu la nga ni ku huma a tshameke kona, u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 7, text: '“La khumbaka miri wa munhu la nga ni ku huma a a hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 8, text: '“Loko la nga ni ku huma a ha ku huma hi mati eka munhu la tengaka, la nga ha humaka a a hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 9, text: '“Xikwelo xin’wana ni xin’wana lexi a tshamaka eka xona, xi ta va nchumu lowu nyamisaka.”' },
    { n: 10, text: '“Un’wana ni un’wana la khumbaka xin’wana ni xin’wana lexi a tshamaka eka xona u ta va ni nandzu ku fikela nimadyambu; la swi rhwalaka u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 11, text: '“Un’wana ni un’wana la khumbiwaka hi la nga ni ku huma, naswona a nga hlantswanga mavoko ya yena hi mati, u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 12, text: '“Xibya xa vumba lexi khumbiweke hi la nga ni ku huma xi ta tshoviwa; swibye hinkwaswo swa mhandzi swi ta hlantswiwa hi mati.”' },
    { n: 13, text: '“Loko la nga ni ku huma a tengile, a a tibyela masiku ya nhungu eka ku tenga ka yena, a a hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati lama humaka etshurini, a a tenga.”' },
    { n: 14, text: '“Hi siku ra vunhungu, a a teke tinjiwa timbirhi kumbe swiwa-tiva swimbirhi, a a swi nyikela mahlweni ka Yehovha emunyangweni wa tabernakela ya nhlanganiso, a a swi nyikela eka muprista.”' },
    { n: 15, text: '“Muprista a a swi nyikela, xin’we xa xidyoho, ni xin’we xa xitlhavelo xo hisiwa; muprista a a yi endlele mukutsulo mahlweni ka Yehovha hikwalaho ka ku huma ka miri wa yena.”' },
    { n: 16, text: '“Loko wanuna a humeriwa hi mbewu, a a hlantswa miri wa yena hinkwawo hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 17, text: '“Tinguvu hinkwato, kumbe dzovo hinkwaro, leswi mbewu yi welaka eka swona, swi ta hlantswiwa hi mati, swi ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 18, text: '“Wansati la etlelaka na wanuna la humeriweke hi mbewu, va ta hlantswa miri wa vona hi mati, va ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 19, text: '“Wansati la nga ni ku huma ka ngati, tanihi ku huma ka miri wa yena, u ta va ni nandzu masiku ya 7; un’wana ni un’wana la khumbaka a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 20, text: '“Hinkwaswo leswi a tshamaka eka swona loko a ri eku humeni ku ta va ni nandzu; hinkwaswo leswi a etlelaka eka swona swi ta va ni nandzu.”' },
    { n: 21, text: '“Un’wana ni un’wana la khumbaka mubedo wa yena u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 22, text: '“Un’wana ni un’wana la khumbaka xitulo xin’wana ni xin’wana lexi a tshamaka eka xona u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 23, text: '“Loko ku ri mubedo kumbe xitulo lexi a tshamaka eka xona, un’wana ni un’wana la swi khumbaka u ta va ni nandzu ku fikela nimadyambu.”' },
    { n: 24, text: '“Loko wanuna a etlela na yena, naswona ku nyamisa ka yena ku wela eka yena, u ta va ni nandzu masiku ya 7; mubedo hinkwawo lowu a etlelaka eka wona wu ta va ni nandzu.”' },
    { n: 25, text: '“Loko wansati a humeriwa hi ngati masiku yo tala, hambi ku nga ri hi nkarhi wa ku huma ka yena, kumbe a humeriwa endzhaku ka nkarhi wa yena, masiku hinkwato ya ku huma ka yena ma ta fana ni masiku ya ku nyamisa ka yena; u ta va ni nandzu.”' },
    { n: 26, text: '“Mubedo hinkwawo lowu a etlelaka eka wona masiku ya ku huma ka yena wu ta fana ni mubedo wa ku huma ka yena; xitulo xin’wana ni xin’wana lexi a tshamaka eka xona xi ta va ni nandzu, tanihi ku nyamisa ka ku huma ka yena.”' },
    { n: 27, text: '“Un’wana ni un’wana la swi khumbaka u ta va ni nandzu; u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu.”' },
    { n: 28, text: '“Loko a tengile eka ku huma ka yena, a a tibyela masiku ya 7, endzhaku ka sweswo a a tenga.”' },
    { n: 29, text: '“Hi siku ra vunhungu, a a teke tinjiwa timbirhi kumbe swiwa-tiva swimbirhi, a a swi tisa eka muprista, emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 30, text: '“Muprista a a swi nyikela, xin’we xa xidyoho, ni xin’we xa xitlhavelo xo hisiwa; muprista a a yi endlele mukutsulo mahlweni ka Yehovha hikwalaho ka ku huma ka ku nyamisa ka yena.”' },
    { n: 31, text: '“Mi ta hambanisa vana va Israyele ni ku nyamisa ka vona, leswaku va nga fi eku nyamiseni ka vona, hi ku nyamisa ka tabernakela ya mina leyi nga exikarhi ka vona.”' },
    { n: 32, text: '“Lowu i nawu wa loyi a nga ni ku huma, ni loyi mbewu ya yena yi humaka, naswona a va ni nandzu ha yona;”' },
    { n: 33, text: '“Ni loyi a humeriwaka hi ku nyamisa ka yena, ni loyi a humeriwaka hi ku huma ka ngati, ni wanuna ni wansati, ni wanuna la etlelaka ni wansati la nga ni ku nyamisa.”' }
  ],
  16: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, endzhaku ka ku fa ka vana vambirhi va Aroni, loko va tshinele mahlweni ka Yehovha, va fa;' },
    { n: 2, text: 'Yehovha a ku eka Moxe: “Byela Aroni makwenu, leswaku a nga ngheni hi nkarhi hinkwawo endlwini ya ku kwetsima, eka xipfalu, mahlweni ka xikombo lexi nga ehenhla ka areka, leswaku a nga fi; hikuva ndzi ta humelela erhenjini ehenhla ka xikombo.”' },
    { n: 3, text: '“Aroni a a nghene endlwini ya ku kwetsima hi leswi: Hi xinkunzi xa xidyoho, ni xinyimpfu xa xitlhavelo xo hisiwa.”' },
    { n: 4, text: '“A a ambarile nguvu yo kwetsima ya ntsembe, ni swibulukwana swa ntsembe ehenhla ka miri wa yena, a a bohe nguvu ya lhen’we ya ntsembe, a a bohe xitsongwatsongwana xa ntsembe; leswi i tinguvu to kwetsima, a a hlantswa miri wa yena hi mati, a a swi ambala.”' },
    { n: 5, text: '“A a teke eka nhlengeletano ya vana va Israyele swiphambani swimbirhi swa tinguvu ta n’tshambhu swa xidyoho, ni xinyimpfu xin’we xa xitlhavelo xo hisiwa.”' },
    { n: 6, text: '“Aroni a a nyikela xinkunzi xa xidyoho lexi nga xa yena, a a yi endlele mukutsulo yena ni ndyangu wa yena.”' },
    { n: 7, text: '“A a teke swiphambani swimbirhi, a a swi veka mahlweni ka Yehovha emunyangweni wa tabernakela ya nhlanganiso.”' },
    { n: 8, text: '“A a hoxa vuhlolotwana eka swiphambani swimbirhi, vun’we bya Yehovha, ni vun’we bya Azazele.”' },
    { n: 9, text: '“Aroni a a teke xiphambani lexi vuhlolotwana byi humeleke eka Yehovha, a a xi nyikela tanihi xidyoho.”' },
    { n: 10, text: '“Kambe xiphambani lexi vuhlolotwana byi humeleke eka Azazele, a a xi veka xi ri xikwetsimi mahlweni ka Yehovha, a a xi tshika xi ya eka Azazele emananga.”' },
    { n: 11, text: '“Aroni a a tisa xinkunzi xa xidyoho lexi nga xa yena, a a yi endlele mukutsulo yena ni ndyangu wa yena, a a tlhave xinkunzi xa xidyoho lexi nga xa yena.”' },
    { n: 12, text: '“A a teke xibye xa malahla lama hisaka lama humaka ealitari mahlweni ka Yehovha, ni swiphemu swimbirhi swa risuna ro nun’hwela, a a swi nghenisa eka xipfalu;”' },
    { n: 13, text: '“A a veka risuna mahlweni ka Yehovha, leswaku papa ra risuna ri funengeta xikombo lexi nga ehenhla ka vumbhoni, leswaku a nga fi.”' },
    { n: 14, text: '“A a teke eka ngati ya xinkunzi, a a fafata hi munwe wa yena ehenhla ka xikombo evuxeni; mahlweni ka xikombo a a fafata ngati makhamba ya nhungu hi munwe wa yena.”' },
    { n: 15, text: '“A a tlhave xiphambani xa xidyoho lexi nga xa vanhu, a a nghenisa ngati ya xona eka xipfalu, a a endla hi ngati ya xona tanihi leswi a endleke hi ngati ya xinkunzi, a a xi fafata ehenhla ka xikombo, ni mahlweni ka xikombo;”' },
    { n: 16, text: '“A a yi endlele mukutsulo yindlu ya ku kwetsima, hikwalaho ka ku nyamisa ka vana va Israyele, ni hikwalaho ka swidyoho swa vona, ni swidyoho hinkwaswo swa vona; a a endla hi ndlela leyi hi tabernakela ya nhlanganiso, leyi tshamaka na vona exikarhi ka ku nyamisa ka vona.”' },
    { n: 17, text: '“A ku nge vi na munhu endlwini ya ku kwetsima loko a nghena leswaku a ya endla mukutsulo, ku fikela loko a huma, a a yi endlele mukutsulo yena, ni ndyangu wa yena, ni nhlengeletano hinkwayo ya Israyele.”' },
    { n: 18, text: '“A a huma a ya ealitari leyi nga mahlweni ka Yehovha, a a yi endlele mukutsulo; a a teke eka ngati ya xinkunzi, ni eka ngati ya xiphambani, a a chela etimponjini ta alitari hinkwayo.”' },
    { n: 19, text: '“A a fafata ngati makhamba ya nhungu hi munwe wa yena, a a yi basisa, a a yi kwetsimisa eka ku nyamisa ka vana va Israyele.”' },
    { n: 20, text: '“Endzhaku ka loko a hete ku endla mukutsulo wa yindlu ya ku kwetsima, ni tabernakela ya nhlanganiso, ni alitari, a a tisa xiphambani lexi hanyaka;”' },
    { n: 21, text: '“A a veka mavoko ya yena mambirhi enhlokweni ya xiphambani lexi hanyaka, a a tivula swidyoho hinkwaswo swa vana va Israyele, ni swidyoho hinkwaswo swa vona, swidyoho hinkwaswo swa vona; a a swi veka enhlokweni ya xiphambani, a a xi humesa hi voko ra munhu loyi a a xi lungiselele emananga.”' },
    { n: 22, text: '“Xiphambani xi ta rhwala swidyoho hinkwaswo swa vona eka tiko leri nga riki na munhu; a a xi tshika emananga.”' },
    { n: 23, text: '“Aroni a a nghena eka tabernakela ya nhlanganiso, a a hluvula tinguvu ta ntsembe leti a ti ambarile loko a nghena eka yindlu ya ku kwetsima, a a ti veka kwalaho.”' },
    { n: 24, text: '“A a hlantswa miri wa yena hi mati endhawini yo kwetsima, a a ambala tinguvu ta yena, a a huma, a a nyikela xitlhavelo xo hisiwa xa yena, ni xitlhavelo xo hisiwa xa vanhu, a a yi endlela mukutsulo yena ni vanhu.”' },
    { n: 25, text: '“Mafurha ya xidyoho a a ma hisa ealitari.”' },
    { n: 26, text: '“La humeseke xiphambani eka Azazele a a hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, endzhaku ka sweswo a a nghena enkambini.”' },
    { n: 27, text: '“Xinkunzi xa xidyoho, ni xiphambani xa xidyoho, leswi ngati ya swona yi tisiweke ku endla mukutsulo endlwini ya ku kwetsima, swi ta humesiwa ehandle ka nkambi; va ta hisa hi ndzilo dzovo ra swona, ni nyama ya swona, ni thyaka ra swona.”' },
    { n: 28, text: '“La swi hisaka a a hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, endzhaku ka sweswo a a nghena enkambini.”' },
    { n: 29, text: '“Lowu i nawu wa hilaha ku nga heriki eka n’wina: Hi n’hweti ya 7, hi siku ra 10 ra n’hweti, mi ta titsona swakudya, mi nga endli ntirho wun’wana, hambi a ri munhu wa tiko, hambi a ri munhu wa matiko mambe loyi a tshamaka exikarhi ka n’wina.”' },
    { n: 30, text: '“Hikuva hi siku leri, va ta mi endlela mukutsulo, leswaku mi tenga; mi ta tenga eka swidyoho hinkwaswo swa n’wina mahlweni ka Yehovha.”' },
    { n: 31, text: '“I savata ya ku wisela, mi ta titsona swakudya; lowu i nawu wa hilaha ku nga heriki.”' },
    { n: 32, text: '“Muprista loyi a totiweke, ni loyi a vekiweke leswaku a tirha tanihi muprista la landzelaka tata wa yena, a a endla mukutsulo, a a ambala tinguvu ta ntsembe, tinguvu to kwetsima;”' },
    { n: 33, text: '“A a endla mukutsulo wa yindlu ya ku kwetsima, a a endla mukutsulo wa tabernakela ya nhlanganiso, ni wa alitari, a a endla mukutsulo wa vaprista, ni wa vanhu hinkwavo va nhlengeletano.”' },
    { n: 34, text: '“Lowu i nawu wa hilaha ku nga heriki eka n’wina, leswaku mi endla mukutsulo wa vana va Israyele hikwalaho ka swidyoho hinkwaswo swa vona, kambirhi hi lembe.”' },
    { n: 35, text: 'A a endla hilaha Yehovha a leriseke Moxe ha kona.' }
  ],
  17: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula na Aroni, ni vana va Israyele, mi ku eka vona: Lowu i nawu lowu Yehovha a wu leriseke, a ku:”' },
    { n: 3, text: '“Wanuna un’wana ni un’wana wa yindlu ya Israyele, loyi a tlhavaka xinkunzi, kumbe xinyimpfu, kumbe mbuti, enkambini, kumbe la tlhavaka ehandle ka nkambi;”' },
    { n: 4, text: '“Naswona a nga swi tisanga emunyangweni wa tabernakela ya nhlanganiso, leswaku a swi nyikela mahlweni ka Yehovha, mahlweni ka tabernakela ya Yehovha; munhu yoloye u ta va ni nandzu wa ngati, u chulule ngati; munhu yoloye u ta susiwa exikarhi ka vanhu va ka vona.”' },
    { n: 5, text: '“Leswaku vana va Israyele va tisa switlhavelo swa vona leswi va swi tlhavaka emasin’wini, va swi tisa eka Yehovha, emunyangweni wa tabernakela ya nhlanganiso, eka muprista, va swi tlhavela Yehovha tanihi switlhavelo swa ku rhula.”' },
    { n: 6, text: '“Muprista a a chela ngati ealitari ya Yehovha, emunyangweni wa tabernakela ya nhlanganiso, a a hisa mafurha tanihi risuna ro nun’hwela eka Yehovha.”' },
    { n: 7, text: '“A va nga ha tlhaveli swikwembu swa hava, leswi va nga landza swona hi vumbhandzi; lowu i nawu wa hilaha ku nga heriki eka vona, eswitsungeni swa vona.”' },
    { n: 8, text: '“U ta ku eka vona: Wanuna un’wana ni un’wana wa yindlu ya Israyele, kumbe wa matiko mambe lawa ma tshamaka exikarhi ka n’wina, loyi a nyikelaka xitlhavelo xo hisiwa kumbe xitlhavelo;”' },
    { n: 9, text: '“Naswona a nga swi tisanga emunyangweni wa tabernakela ya nhlanganiso, leswaku a swi nyikela eka Yehovha; munhu yoloye u ta susiwa exikarhi ka vanhu va ka vona.”' },
    { n: 10, text: '“Wanuna un’wana ni un’wana wa yindlu ya Israyele, kumbe wa matiko mambe lawa ma tshamaka exikarhi ka n’wina, loyi a dyaka ngati ya mixaka hinkwayo, ndzi ta lwisana ni munhu yoloye la dyaka ngati, ndzi ta n’wi susa exikarhi ka vanhu va ka vona.”' },
    { n: 11, text: '“Hikuva moya wa miri i ngati; ndzi mi nyike yona ealitari, leswaku mi endla mukutsulo wa mimoya ya n’wina; hikuva ngati yi endla mukutsulo hi moya.”' },
    { n: 12, text: '“Hikwalaho ndzi vule eka vana va Israyele: A ku na un’wana exikarhi ka n’wina loyi a nga ta dya ngati, hambi a ri munhu wa matiko mambe loyi a tshamaka exikarhi ka n’wina, a a nga dyi ngati.”' },
    { n: 13, text: '“Wanuna un’wana ni un’wana wa vana va Israyele, kumbe wa matiko mambe lawa ma tshamaka exikarhi ka n’wina, loyi a khomaka xihari kumbe xinyenyana lexi dyiwaka, a a chulula ngati ya xona, a a xi funengeta hi ntshuri.”' },
    { n: 14, text: '“Hikuva moya wa miri hinkwawo i ngati ya wona, moya wa wona i ngati ya wona; hikwalaho ndzi vule eka vana va Israyele: Mi nga dyi ngati ya mixaka hinkwayo ya miri, hikuva moya wa miri hinkwawo i ngati ya wona; un’wana ni un’wana la yi dyaka u ta susiwa.”' },
    { n: 15, text: '“Un’wana ni un’wana la dyaka nchumu lowu feke kumbe lowu tlhaviweke hi swivandzana, hambi a ri munhu wa tiko, hambi a ri munhu wa matiko mambe, u ta hlantswa tinguvu ta yena, a a hlantswa miri wa yena hi mati, a a va ni nandzu ku fikela nimadyambu, endzhaku ka sweswo a a tenga.”' },
    { n: 16, text: '“Kambe loko a nga yi hlantswanga, naswona a nga hlantswanga miri wa yena, u ta va ni nandzu.”' }
  ],
  18: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 3, text: '“Mi nga endli hilaha va endlaka ha kona etikweni ra Egipta, leri mi tshamaka eka rona, mi nga endli hilaha va endlaka ha kona etikweni ra Kanana, leri ndzi mi yisaka eka rona; mi nga fambi hi milawu ya vona.”' },
    { n: 4, text: '“Mi ta endla hi swileriso swa mina, mi hlayisa milawu ya mina, leswaku mi famba ha yona; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 5, text: '“Mi ta hlayisa milawu ya mina, ni swileriso swa mina, leswi munhu a endlaka ha swona, a ta hanya ha swona; hi mina Yehovha.”' },
    { n: 6, text: '“Un’wana ni un’wana wa n’wina a nga tshinele eka xirho xa miri wa munhu wa ka vona, leswaku a va ni vumbhandzi; hi mina Yehovha.”' },
    { n: 7, text: '“U nga va ni vumbhandzi ni tata wa wena, kumbe ni mana wa wena; i mana wa wena, u nga va ni vumbhandzi na yena.”' },
    { n: 8, text: '“U nga va ni vumbhandzi ni nsati wa tata wa wena; i vumbhandzi bya tata wa wena.”' },
    { n: 9, text: '“U nga va ni vumbhandzi ni makwenu wa xisati, n’wana wa tata wa wena, kumbe n’wana wa mana wa wena, hambi va tswariwe eka yindlu kumbe ehandle, u nga va ni vumbhandzi na vona.”' },
    { n: 10, text: '“U nga va ni vumbhandzi ni n’wana wa n’wana wa wena wa xinuna, kumbe n’wana wa n’wana wa wena wa xisati, hikuva i vumbhandzi bya wena.”' },
    { n: 11, text: '“U nga va ni vumbhandzi ni n’wana wa nsati wa tata wa wena, n’wana wa tata wa wena, i makwenu wa wena, u nga va ni vumbhandzi na yena.”' },
    { n: 12, text: '“U nga va ni vumbhandzi ni makwenu wa tata wa wena, i n’wana wa tata wa wena.”' },
    { n: 13, text: '“U nga va ni vumbhandzi ni makwenu wa mana wa wena, hikuva i n’wana wa mana wa wena.”' },
    { n: 14, text: '“U nga va ni vumbhandzi ni makwenu wa tata wa wena, u nga tshinele eka nsati wa yena, i makwenu wa tata wa wena.”' },
    { n: 15, text: '“U nga va ni vumbhandzi ni n’wana wa wena wa xisati, i nsati wa n’wana wa wena, u nga va ni vumbhandzi na yena.”' },
    { n: 16, text: '“U nga va ni vumbhandzi ni nsati wa makwenu wa tata wa wena, i vumbhandzi bya makwenu wa tata wa wena.”' },
    { n: 17, text: '“U nga va ni vumbhandzi ni wansati ni n’wana wa yena, u nga teki n’wana wa n’wana wa yena wa xinuna, kumbe n’wana wa n’wana wa yena wa xisati, leswaku u va ni vumbhandzi na vona; i vumbhandzi bya yena.”' },
    { n: 18, text: '“U nga teki wansati ni makwenu wa yena, leswaku u va ni vumbhandzi na yena, eka vutomi bya yena.”' },
    { n: 19, text: '“U nga tshinele eka wansati hi nkarhi wa ku nyamisa ka yena, leswaku u va ni vumbhandzi na yena.”' },
    { n: 20, text: '“U nga va ni vumbhandzi ni nsati wa munhu un’wana, leswaku u va ni nandzu ha yena.”' },
    { n: 21, text: '“U nga nyikeli n’wana wa wena wa xinuna kumbe wa xisati eka Moleke, leswaku u nga nyamisi vito ra Xikwembu xa wena; hi mina Yehovha.”' },
    { n: 22, text: '“U nga va ni vumbhandzi ni wanuna hilaha u nga ni vumbhandzi ni wansati; i nchumu lowu nyamisaka.”' },
    { n: 23, text: '“U nga va ni vumbhandzi ni xivandzana, leswaku u nyamisa ha xona; wansati a nga tshinele eka xivandzana leswaku a va ni vumbhandzi na xona; i nchumu lowu nyamisaka.”' },
    { n: 24, text: '“Mi nga tiyendli mi nga tengangiki hi hinkwaswo sweswo; hikuva matiko lawa ndzi ma humesaka mahlweni ka n’wina ma endle swilo leswi hinkwaswo;”' },
    { n: 25, text: '“Naswona tiko ri nyamisile; hikwalaho ndzi ta ri ba hi nandzu wa rona, naswona tiko ri ta humesa vaaki va rona.”' },
    { n: 26, text: '“Mi ta hlayisa milawu ya mina, ni swileriso swa mina, mi nga endli nchumu ni xin’we xa swilo leswi swa ku nyamisa, hambi a ri munhu wa tiko, hambi a ri munhu wa matiko mambe loyi a tshamaka exikarhi ka n’wina;”' },
    { n: 27, text: '“(Hikuva vanhu va tiko leri va endle swilo leswi hinkwaswo swa ku nyamisa, swilo leswi tiko ri nyamisile ha swona;)”' },
    { n: 28, text: '“Leswaku tiko ri nga mi humesi loko mi ri nyamisa, hilaha ri humeseke matiko lawa a ma ri mahlweni ka n’wina.”' },
    { n: 29, text: '“Hikuva un’wana ni un’wana loyi a endlaka nchumu ni xin’we xa swilo leswi swa ku nyamisa, mimoya leyi endlaka sweswo yi ta susiwa exikarhi ka vanhu va ka vona.”' },
    { n: 30, text: '“Mi ta hlayisa nawu wa mina, leswaku mi nga endli nchumu ni xin’we xa swilo leswi swa ku nyamisa, leswi va swi endleke mahlweni ka n’wina, leswaku mi nga tiyendli mi nga tengangiki ha swona; hi mina Yehovha Xikwembu xa n’wina.”' }
  ],
19: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni nhlengeletano hinkwayo ya vana va Israyele, u ku eka vona: Mi ta va vakwetsimi, hikuva hi mina Yehovha Xikwembu xa n’wina, ndza kwetsima.”' },
    { n: 3, text: '“Un’wana ni un’wana wa n’wina a a hloniphe mana wa yena ni tata wa yena, naswona mi ta hlayisa tisavata ta mina; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 4, text: '“Mi nga landzi swikwembu swa hava, mi nga tiendli swikwembu swa nsuku; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 5, text: '“Loko mi nyikela xitlhavelo xa ku rhula eka Yehovha, mi ta xi nyikela leswaku xi amukeleka eka n’wina.”' },
    { n: 6, text: '“Xi ta dyeriwa hi siku leri mi xi nyikelaka ha rona, ni hi siku ra le ndzhaku; kambe leswi swi salaka ku fikela hi siku ra vunharhu swi ta hisiwa hi ndzilo.”' },
    { n: 7, text: '“Loko xi dyiwa hi siku ra vunharhu, xi ta va nchumu lowu nyamisaka, a xi nge amukeleki.”' },
    { n: 8, text: '“Un’wana ni un’wana la xi dyaka u ta rhwala nandzu wa yena, hikuva u nyamisile leswo kwetsima swa Yehovha; munhu yoloye u ta susiwa exikarhi ka vanhu va ka vona.”' },
    { n: 9, text: '“Loko mi tshovela ntshovelo wa tiko ra n’wina, mi nga tshoveli etlhelweni ra masin’wini ya n’wina, mi nga hlengeleti leswi seleke eku tshoveleni ka n’wina.”' },
    { n: 10, text: '“Mi nga hlengeleti masinya ya n’wina ya vhinya, mi nga hlengeleti leswi weleke emisaveni; mi ta swi siyela xisiwana ni munhu wa matiko mambe; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 11, text: '“Mi nga yivi, mi nga hembi, mi nga kanganyisi munhu hi n’wina.”' },
    { n: 12, text: '“Mi nga hlambanyi hi vito ra mina leswi nga riki ntiyiso, mi nga nyamisi vito ra Xikwembu xa n’wina; hi mina Yehovha.”' },
    { n: 13, text: '“Mi nga kangi munhu wa n’wina, mi nga yivi; hakelo ya xitirhi a yi nga sali etlhelweni ra n’wina ku fikela nimixo.”' },
    { n: 14, text: '“Mi nga rhukani ximumu, mi nga veki xikunwana mahlweni ka xihangele; mi ta chava Xikwembu xa n’wina; hi mina Yehovha.”' },
    { n: 15, text: '“Mi nga endli ku nga lulami eku avanyiseni; mi nga hloniphi xisiwana, mi nga xiximi lonkulu; mi ta avanyisa munhu wa n’wina hi ku lulama.”' },
    { n: 16, text: '“Mi nga fambi mi hembela vanhu va ka n’wina, mi nga yimi eka ngati ya munhu wa n’wina; hi mina Yehovha.”' },
    { n: 17, text: '“Mi nga vengani makwenu embilwini ya n’wina; mi ta tsundzuxa munhu wa n’wina, leswaku mi nga rhwali nandzu hi ku n’wi khumbisa.”' },
    { n: 18, text: '“Mi nga rihiseli, mi nga hlayiseli vana va vanhu va ka n’wina vukarhi; mi ta rhandza munhu wa n’wina tanihi loko mi ti rhandza; hi mina Yehovha.”' },
    { n: 19, text: '“Mi ta hlayisa milawu ya mina. Mi nga tlhavisi swifuwo swa n’wina hi mixaka yo hambana, mi nga byari masin’wini ya n’wina hi mbewu ya mixaka mimbirhi, mi nga ambali tinguvu leti lukiweke hi thyaka ra mixaka mimbirhi.”' },
    { n: 20, text: '“Loko wanuna a etlela ni wansati loyi a nga ni vumbhandzi, naswona a nga kutsuriwanga, a nga nyikiwanga ntshunxeko; va ta biwa, kambe va nga fi, hikuva a nga ri ntsunxekanga.”' },
    { n: 21, text: '“U ta tisa xitlhavelo xa nandzu eka Yehovha, emunyangweni wa tabernakela ya nhlanganiso, xinyimpfu xa xitlhavelo xa nandzu.”' },
    { n: 22, text: '“Muprista a a yi endlele mukutsulo hi xinyimpfu xa xitlhavelo xa nandzu mahlweni ka Yehovha, hikwalaho ka xidyoho lexi a xi endleke; a a rivaleriwa xidyoho lexi a xi endleke.”' },
    { n: 23, text: '“Loko mi nghena etikweni, mi byara miri ya mixaka hinkwayo ya swakudya, mi ta hlayisa mihandzu ya yona tanihi nchumu lowu nga tengangiki; masiku ya mambirhi ya ntlhanu mi ta yi hlayisa tanihi nchumu lowu nga tengangiki, mi nga yi dyi.”' },
    { n: 24, text: '“Naswona hi lembe ra vumune mihandzu hinkwayo ya yona yi ta va yo kwetsima, tanihi munyikelo wa ku nkhensa eka Yehovha.”' },
    { n: 25, text: '“Naswona hi lembe ra vuntlhanu mi ta dya mihandzu ya yona, leswaku yi mi engetelela; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 26, text: '“Mi nga dyi nchumu hi ngati; mi nga hloleli, mi nga endli vuhlolo.”' },
    { n: 27, text: '“Mi nga tsemi matluka ya tinhloko ta n’wina, mi nga tsemi mikhumburhi ya n’wina.”' },
    { n: 28, text: '“Mi nga tsemi miri wa n’wina hikwalaho ka loyi a feke, mi nga tiendli mavala, hi mina Yehovha.”' },
    { n: 29, text: '“Mi nga nyamisi n’wana wa n’wina wa xisati hi ku n’wi endla ntsumi, leswaku tiko ri nga tiyendli ri nga tengangiki, naswona tiko ri nga tali hi vuhomboloki.”' },
    { n: 30, text: '“Mi ta hlayisa tisavata ta mina, mi xixima yindlu ya mina yo kwetsima; hi mina Yehovha.”' },
    { n: 31, text: '“Mi nga languti vahloli, mi nga vutisi vahlahluvi, leswaku mi nga tiyendli mi nga tengangiki ha vona; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 32, text: '“Mi ta yima mahlweni ka munhu la dyuhaleke, mi xixima nkulu, mi ta chava Xikwembu xa n’wina; hi mina Yehovha.”' },
    { n: 33, text: '“Loko munhu wa matiko mambe a tshama na n’wina etikweni, mi nga n’wi kangi.”' },
    { n: 34, text: '“Munhu wa matiko mambe loyi a tshamaka na n’wina u ta va eka n’wina tanihi munhu wa tiko, mi ta n’wi rhandza tanihi loko mi ti rhandza; hikuva a mi ri vahlaluki etikweni ra Egipta; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 35, text: '“Mi nga endli ku nga lulami eku pimekeni, hi xipimo, kumbe hi xihimo, kumbe hi mati.”' },
    { n: 36, text: '“Mi ta va ni xipimo xa ntiyiso, ni xihimo xa ntiyiso, ni mati ya ntiyiso; hi mina Yehovha Xikwembu xa n’wina, loyi a mi humeseke etikweni ra Egipta.”' },
    { n: 37, text: '“Mi ta hlayisa milawu ya mina hinkwayo, ni swileriso swa mina hinkwaswo, mi swi endla; hi mina Yehovha.”' }
  ],
  20: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Un’wana ni un’wana wa vana va Israyele, kumbe wa matiko mambe lawa ma tshamaka exikarhi ka n’wina, loyi a nyikelaka n’wana wa yena eka Moleke, u ta dlayiwa; vanhu va tiko va ta n’wi ba hi maribye.”' },
    { n: 3, text: '“Ndzi ta lwisana ni munhu yoloye, ndzi ta n’wi susa exikarhi ka vanhu va ka vona, hikuva u nyike n’wana wa yena eka Moleke, leswaku a nyamisa yindlu ya mina yo kwetsima, naswona a nyamisa vito ra mina ro kwetsima.”' },
    { n: 4, text: '“Loko vanhu va tiko va pfala mahlo ya vona eka munhu yoloye loyi a nyikaka n’wana wa yena eka Moleke, naswona va nga n’wi dlayi;”' },
    { n: 5, text: '“Ndzi ta lwisana ni munhu yoloye ni ndyangu wa yena, ndzi ta n’wi susa exikarhi ka vanhu va ka vona, ni hinkwavo lava va n’wi landzelaka hi vumbhandzi eka Moleke.”' },
    { n: 6, text: '“Moya lowu yaka eka vahloli ni vahlahluvi, leswaku va va landza hi vumbhandzi, ndzi ta lwisana ni moya yoloye, ndzi ta n’wi susa exikarhi ka vanhu va ka vona.”' },
    { n: 7, text: '“Mi ta tiyendla mi kwetsima, mi va vakwetsimi; hikuva hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 8, text: '“Mi ta hlayisa milawu ya mina, mi yi endla; hi mina Yehovha, loyi a mi kwetsimisaka.”' },
    { n: 9, text: '“Un’wana ni un’wana la rhukanaka tata wa yena kumbe mana wa yena u ta dlayiwa; u rhukane tata wa yena ni mana wa yena, ngati ya yena yi le henhla ka yena.”' },
    { n: 10, text: '“Wanuna loyi a etlelaka ni nsati wa munhu un’wana, loyi a etlelaka ni nsati wa munhu wa ka vona, wanuna ni wansati lava etlelaka va ta dlayiwa.”' },
    { n: 11, text: '“Wanuna loyi a etlelaka ni nsati wa tata wa yena, u nyamisile tata wa yena; hinkwavo lava va ta dlayiwa, ngati ya vona yi le henhla ka vona.”' },
    { n: 12, text: '“Wanuna loyi a etlelaka ni n’wana wa nsati wa yena wa xisati, hinkwavo lava va ta dlayiwa; va endle nchumu lowu nyamisaka, ngati ya vona yi le henhla ka vona.”' },
    { n: 13, text: '“Wanuna loyi a etlelaka ni wanuna hilaha a etlelaka ni wansati, va endle nchumu lowu nyamisaka; hinkwavo lava va ta dlayiwa, ngati ya vona yi le henhla ka vona.”' },
    { n: 14, text: '“Wanuna loyi a tekaka wansati ni mana wa yena, i nchumu lowu nyamisaka; va ta hisiwa hi ndzilo, yena ni vona, leswaku ku nga vi na nchumu lowu nyamisaka exikarhi ka n’wina.”' },
    { n: 15, text: '“Wanuna loyi a etlelaka ni xivandzana u ta dlayiwa, naswona mi ta dlaya xivandzana.”' },
    { n: 16, text: '“Wansati loyi a tshinele eka xivandzana leswaku a va ni vumbhandzi na xona, u ta dlaya wansati ni xivandzana; hinkwavo lava va ta dlayiwa, ngati ya vona yi le henhla ka vona.”' },
    { n: 17, text: '“Wanuna loyi a tekaka makwenu wa xisati, n’wana wa tata wa yena, kumbe n’wana wa mana wa yena, naswona a vona vumbhandzi bya yena, naswona a vona vumbhandzi bya yena, i nchumu lowu nyamisaka; va ta susiwa mahlweni ka vanhu va ka vona; u vonile vumbhandzi bya makwenu wa xisati, u ta rhwala nandzu wa yena.”' },
    { n: 18, text: '“Wanuna loyi a etlelaka ni wansati hi nkarhi wa ku nyamisa ka yena, naswona a vona vumbhandzi bya yena, u pfulile xihlovo xa yena, naswona wansati u pfulile xihlovo xa ngati ya yena; hinkwavo lava va ta susiwa exikarhi ka vanhu va ka vona.”' },
    { n: 19, text: '“U nga va ni vumbhandzi ni makwenu wa mana wa wena, kumbe ni makwenu wa tata wa wena, hikuva u nyamisile vumbhandzi bya wena; va ta rhwala nandzu wa vona.”' },
    { n: 20, text: '“Wanuna loyi a etlelaka ni nsati wa makwenu wa tata wa wena, u nyamisile vumbhandzi bya makwenu wa tata wa wena; va ta rhwala xidyoho xa vona, va ta fa va nga ri na vana.”' },
    { n: 21, text: '“Wanuna loyi a tekaka nsati wa makwenu wa tata wa wena, i nchumu lowu nyamisaka; u nyamisile vumbhandzi bya makwenu wa tata wa wena; va ta fa va nga ri na vana.”' },
    { n: 22, text: '“Mi ta hlayisa milawu ya mina hinkwayo, ni swileriso swa mina hinkwaswo, mi swi endla; leswaku tiko leri ndzi mi yisaka eka rona leswaku mi tshama eka rona, ri nga mi humesi.”' },
    { n: 23, text: '“Mi nga fambi hi milawu ya matiko lawa ndzi ma humesaka mahlweni ka n’wina; hikuva va endle swilo leswi hinkwaswo, hikwalaho ndzi va vengile.”' },
    { n: 24, text: '“Kambe ndzi ku eka n’wina: Mi ta dya tiko ra vona, ndzi ta mi nyika rona tanihi ndzhaka, tiko leri humesaka swakudya swa vutomi; hi mina Yehovha Xikwembu xa n’wina, loyi a mi hambaniseke ni matiko man’wana.”' },
    { n: 25, text: '“Mi ta hambanisa swifuwo leswi tengeke ni leswi nga tengangiki, ni tinyenyana leti tengeke ni leti nga tengangiki; mi nga tiyendli mi nga tengangiki hi swifuwo, kumbe hi tinyenyana, kumbe hi nchumu lowu hohlovaka emisaveni, leswi ndzi swi hambaniseke eka n’wina tanihi swilo leswi nga tengangiki.”' },
    { n: 26, text: '“Mi ta va vakwetsimi eka mina, hikuva hi mina Yehovha, ndza kwetsima, ndzi mi hambanise eka matiko man’wana, leswaku mi va va mina.”' },
    { n: 27, text: '“Wanuna kumbe wansati loyi a nga ni moya wa vahloli kumbe wa vahlahluvi u ta dlayiwa; va ta va ba hi maribye, ngati ya vona yi le henhla ka vona.”' }
  ],
  21: [
    { n: 1, text: 'Yehovha a ku eka Moxe: “Vulavula ni vaprista, vana va Aroni, u ku eka vona: A ku na muprista loyi a nga ta tiyendla a nga tengangiki hikwalaho ka loyi a feke exikarhi ka vanhu va ka vona;”' },
    { n: 2, text: '“Kambe hikwalaho ka munhu wa le ndyangwini wa yena, loyi a nga kusuhi na yena, hikwalaho ka tata wa yena, kumbe mana wa yena, kumbe n’wana wa yena wa xinuna, kumbe wa xisati, kumbe makwenu wa yena;”' },
    { n: 3, text: '“Ni hikwalaho ka makwenu wa yena wa xisati, loyi a nga riki na nuna, loyi a nga kusuhi na yena, a a tiyendla a nga tengangiki hikwalaho ka yena.”' },
    { n: 4, text: '“A nga tiyendli a nga tengangiki exikarhi ka vanhu va ka vona, leswaku a nyamisa vukwetsimi bya yena.”' },
    { n: 5, text: '“Va nga tsemi matluka ya tinhloko ta vona, va nga tsemi mikhumburhi ya vona, va nga tiendli mavala eka miri wa vona.”' },
    { n: 6, text: '“Va ta va vakwetsimi eka Xikwembu xa vona, va nga nyamisi vito ra Xikwembu xa vona; hikuva va nyikela switlhavelo swa ndzilo swa Yehovha, swakudya swa Xikwembu xa vona, hikwalaho va ta va vakwetsimi.”' },
    { n: 7, text: '“Va nga teki wansati loyi a nga ni vumbhandzi, kumbe loyi a nga tengangiki, va nga teki wansati loyi a hlongoriweke hi nuna wa yena; hikuva muprista i wokwetsima eka Xikwembu xa yena.”' },
    { n: 8, text: '“U ta n’wi kwetsimisa, hikuva u nyikela swakudya swa Xikwembu xa wena; u ta va wokwetsima eka wena, hikuva hi mina Yehovha, loyi a mi kwetsimisaka, ndza kwetsima.”' },
    { n: 9, text: '“N’wana wa muprista loyi a tiyendleke a nga tengangiki hi vumbhandzi, u nyamisile tata wa yena, u ta hisiwa hi ndzilo.”' },
    { n: 10, text: '“Muprista lonkulu exikarhi ka vamakwenu, loyi mafurha ya ku tota ma cheliweke enhlokweni ya yena, ni loyi a ambarisiweke tinguvu to kwetsima, a nga tsemi matluka ya nhloko ya yena, a nga hluvuli tinguvu ta yena;”' },
    { n: 11, text: '“A nga tshinele eka loyi a feke, a nga tiyendli a nga tengangiki hikwalaho ka tata wa yena kumbe mana wa yena;”' },
    { n: 12, text: '“A nga humi endlwini ya ku kwetsima, a nga nyamisi yindlu ya ku kwetsima ya Xikwembu xa yena; hikuva mafurha ya ku tota ya Xikwembu xa yena ma le henhla ka yena; hi mina Yehovha.”' },
    { n: 13, text: '“U ta teka wansati loyi a nga ntsunxekeke.”' },
    { n: 14, text: '“A nga teki wansati loyi a nga ni vumbhandzi, kumbe loyi a nga tengangiki, kumbe loyi a hlongoriweke hi nuna wa yena, kambe u ta teka wansati loyi a nga ntsunxekeke exikarhi ka vanhu va ka vona.”' },
    { n: 15, text: '“A nga nyamisi vana va yena exikarhi ka vanhu va ka vona; hikuva hi mina Yehovha, loyi a n’wi kwetsimisaka.”' },
    { n: 16, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 17, text: '“Vulavula na Aroni, u ku: Un’wana ni un’wana wa vana va wena eka tinxaka ta n’wina, loyi a nga ni xilaveko, a nga tshinele leswaku a nyikela swakudya swa Xikwembu xa yena;”' },
    { n: 18, text: '“Hikuva un’wana ni un’wana loyi a nga ni xilaveko, a nga tshinele, hambi a ri munhu loyi a nga ni mahlo yo biha, kumbe munhu loyi a nga ni milenge yo biha, kumbe munhu loyi a nga ni xirho xo biha, kumbe munhu loyi a nga ni xilaveko xo biha,”' },
    { n: 19, text: '“Kumbe munhu loyi a nga ni nenge wo biha, kumbe munhu loyi a nga ni voko ro biha,”' },
    { n: 20, text: '“Kumbe munhu loyi a nga ni xilaveko xa ku tsetselela, kumbe munhu loyi a nga ni vuvabyi bya mahlo, kumbe munhu loyi a nga ni vuvabyi bya nhloko, kumbe munhu loyi a nga ni xilaveko xa miri.”' },
    { n: 21, text: '“Un’wana ni un’wana wa vana va Aroni muprista loyi a nga ni xilaveko, a nga tshinele leswaku a nyikela switlhavelo swa ndzilo swa Yehovha; hikuva u ni xilaveko, a nga tshinele leswaku a nyikela swakudya swa Xikwembu xa yena.”' },
    { n: 22, text: '“U ta dya swakudya swa Xikwembu xa yena, swilo leswo kwetsima swinene, ni swilo leswo kwetsima;”' },
    { n: 23, text: '“Kambe a nga tshinele eka xikombo, a nga tshinele ealitari, hikuva u ni xilaveko, a nga nyamisi yindlu ya mina yo kwetsima; hikuva hi mina Yehovha, loyi a n’wi kwetsimisaka.”' },
    { n: 24, text: 'Moxe a byela Aroni, ni vana va yena, ni vana hinkwavo va Israyele.' }
  ],
  22: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula na Aroni, ni vana va yena, leswaku va tivonela eka swilo leswo kwetsima swa vana va Israyele, leswaku va nga nyamisi vito ra mina ro kwetsima, leswi va swi nyikelaka eka mina; hi mina Yehovha.”' },
    { n: 3, text: '“U ta ku eka vona: Un’wana ni un’wana wa vana va n’wina eka tinxaka ta n’wina, loyi a tshinelelaka swilo leswo kwetsima swa vana va Israyele, leswi va swi nyikelaka eka Yehovha, naswona a ri ni ku nyamisa, munhu yoloye u ta susiwa mahlweni ka mina; hi mina Yehovha.”' },
    { n: 4, text: '“Un’wana ni un’wana wa vana va Aroni loyi a nga ni xiviti, kumbe loyi a humeriwaka hi mati, a nga dyi swilo leswo kwetsima ku fikela loko a tenga; ni loyi a khumbaka loyi a feke, kumbe loyi a humeriwaka hi mbewu;”' },
    { n: 5, text: '“Kumbe loyi a khumbaka nchumu lowu hohlovaka, loyi a nga n’wi nyamisaka, kumbe munhu loyi a nga n’wi nyamisaka, hikwalaho ka ku nyamisa ka yena;”' },
    { n: 6, text: '“Moya loyi a swi khumbaka u ta va ni nandzu ku fikela nimadyambu, a nga dyi swilo leswo kwetsima, kambe a a hlantswa miri wa yena hi mati;”' },
    { n: 7, text: '“Loko dyambu ri pela, u ta tenga, endzhaku ka sweswo a a dya swilo leswo kwetsima, hikuva i swakudya swa yena.”' },
    { n: 8, text: '“A nga dyi nchumu lowu feke kumbe lowu tlhaviweke hi swivandzana, leswaku a nga tiyendli a nga tengangiki; hi mina Yehovha.”' },
    { n: 9, text: '“Va ta hlayisa nawu wa mina, leswaku va nga rhwali nandzu, va nga fi hikwalaho ka sweswo, hikuva ndza va kwetsimisa; hi mina Yehovha.”' },
    { n: 10, text: '“A ku na munhu wa matiko mambe loyi a nga dyaka nchumu lowu kwetsimaka; xitirhi xa muprista, kumbe munhu loyi a hi ntirho, a nga dyi nchumu lowu kwetsimaka.”' },
    { n: 11, text: '“Kambe loko muprista a xava munhu hi mali, u ta dya swakudya swa yena; ni loyi a tswariweke endlwini ya yena, va ta dya swakudya swa yena.”' },
    { n: 12, text: '“Loko n’wana wa muprista a tekiwa hi munhu wa matiko mambe, a nga dyi eka swilo leswo kwetsima leswi nyikeriweke.”' },
    { n: 13, text: '“Kambe loko n’wana wa muprista a ri xisiwana, kumbe a hlongoriwile, naswona a nga na vana, a tlhelela endlwini ya tata wa yena, tanihi vuntshwa bya yena, u ta dya swakudya swa tata wa yena; kambe a ku na munhu wa matiko mambe loyi a nga swi dyaka.”' },
    { n: 14, text: '“Loko munhu a dya nchumu lowu kwetsimaka hi xihoxo, u ta engetela xa ntlhanu eka wona, a a nyika muprista nchumu lowu kwetsimaka.”' },
    { n: 15, text: '“Va nga nyamisi swilo leswo kwetsima swa vana va Israyele, leswi va swi nyikelaka eka Yehovha;”' },
    { n: 16, text: '“Va va rhwalisa nandzu wa swilo leswo kwetsima, loko va swi dya; hikuva hi mina Yehovha, loyi a va kwetsimisaka.”' },
    { n: 17, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 18, text: '“Vulavula na Aroni, ni vana va yena, ni vana hinkwavo va Israyele, u ku eka vona: Un’wana ni un’wana wa vana va Israyele, kumbe wa matiko mambe lawa ma tshamaka exikarhi ka n’wina, loyi a nyikelaka xitlhavelo xo hisiwa, hambi a ri xidyoho xa yena, leswi va swi nyikelaka eka Yehovha tanihi xitlhavelo xo hisiwa;”' },
    { n: 19, text: '“Leswaku xi amukeleka, mi ta nyikela xinkunzi, kumbe xinyimpfu, kumbe mbuti, leyi nga riki na xilaveko.”' },
    { n: 20, text: '“A mi nge nyikeli nchumu lowu nga na xilaveko, hikuva a wu nge amukeleki eka n’wina.”' },
    { n: 21, text: '“Loko munhu a nyikela xitlhavelo xa ku rhula eka Yehovha, leswaku a endla xikombelo, kumbe tanihi munyikelo wa ku tirhandzela, hambi a ri swifuwo, hambi a ri xinyimpfu, xi ta va lexi nga riki na xilaveko leswaku xi amukeleka; a xi nge vi na xilaveko.”' },
    { n: 22, text: '“Leswi nga ni mahlo yo biha, kumbe leswi nga ni nenge wo biha, kumbe leswi nga ni xilaveko xa miri, kumbe leswi nga ni xiviti, kumbe leswi nga ni vuvabyi bya nhloko, leswi a mi nge swi nyikeli eka Yehovha, a mi nge swi hisi ealitari tanihi switlhavelo swa ndzilo eka Yehovha.”' },
    { n: 23, text: '“Xinkunzi kumbe xinyimpfu lexi nga ni xiphemu xo biha, u nga xi nyikela tanihi munyikelo wa ku tirhandzela; kambe tanihi munyikelo wa xikombelo a xi nge amukeleki.”' },
    { n: 24, text: '“Leswi swi nga ni maribye lama tsemiweke, kumbe lama pfalekeke, kumbe lama hlongoriweke, a mi nge swi nyikeli eka Yehovha, a mi nge swi endli etikweni ra n’wina.”' },
    { n: 25, text: '“Naswona eka voko ra munhu wa matiko mambe, a mi nge nyikeli swakudya swa Xikwembu xa n’wina eka hinkwaswo leswi; hikuva swi na xilaveko, swi ni vuvabyi, a swi nge amukeleki eka n’wina.”' },
    { n: 26, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 27, text: '“Loko xinkunzi, kumbe xinyimpfu, kumbe mbuti, xi tswariwa, xi ta tshama ni mana wa xona masiku ya 7; naswona hi siku ra vunhungu, xi ta amukeleka tanihi switlhavelo swa ndzilo eka Yehovha.”' },
    { n: 28, text: '“Hambi xi ri xinkunzi kumbe xinyimpfu, mi nga xi tlhavi, xi ri ni mana wa xona hi siku rin’we.”' },
    { n: 29, text: '“Loko mi nyikela xitlhavelo xa ku nkhensa eka Yehovha, mi xi nyikela leswaku xi amukeleka eka n’wina.”' },
    { n: 30, text: '“Xi ta dyeriwa hi siku rero; a mi nge siyeli nchumu ku fikela nimixo; hi mina Yehovha.”' },
    { n: 31, text: '“Mi ta hlayisa milawu ya mina, mi yi endla; hi mina Yehovha.”' },
    { n: 32, text: '“Mi nga nyamisi vito ra mina ro kwetsima, leswaku ndzi kwetsimisiwa exikarhi ka vana va Israyele; hi mina Yehovha, loyi a mi kwetsimisaka,”' },
    { n: 33, text: '“Loyi a mi humeseke etikweni ra Egipta, leswaku ndzi va Xikwembu xa n’wina; hi mina Yehovha.”' }
  ],
23: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Tinsiku ta nkhuvo ta Yehovha, leti mi nga ta ti tivisa tanihi tinhlengeletano to kwetsima, hi leti tinsiku ta nkhuvo ta mina.”' },
    { n: 3, text: '“Ku ta tirhiwa masiku ya tsevu, kambe siku ra vunkombo i savata ya ku wisanyana, i nhlengeletano yo kwetsima; mi nga endli ntirho lowu nga riki wa nchumu; i savata ya Yehovha emitiyeni hinkwayo ya n’wina.”' },
    { n: 4, text: '“Tinsiku ta nkhuvo ta Yehovha, tinhlengeletano to kwetsima, leti mi nga ta ti tivisa hi minkarhi ya tona, hi leti:”' },
    { n: 5, text: '“Hi n’weti wo sungula, hi siku ra vukhume ni mune ra n’weti, nkarhi wa nimadyambu, i nkhuvo wa phasika wa Yehovha.”' },
    { n: 6, text: '“Naswona hi siku ra vukhume ni ntlhanu ra n’weti lowu, i nkhuvo wa swinkwa leswi nga riki na nchivirisi wa Yehovha; masiku ya ntlhanu na mambirhi mi ta dya swinkwa leswi nga riki na nchivirisi.”' },
    { n: 7, text: '“Hi siku ro sungula mi ta va ni nhlengeletano yo kwetsima; mi nga endli ntirho lowu bikiwaka hi nkhongolo.”' },
    { n: 8, text: '“Mi ta nyikela xitlhavelo xa ndzilo eka Yehovha masiku ya ntlhanu na mambirhi; hi siku ra vunkombo ku ta va ni nhlengeletano yo kwetsima, mi nga endli ntirho lowu bikiwaka hi nkhongolo.”' },
    { n: 9, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 10, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko mi nghena etikweni leri ndzi mi nyikaka rona, naswona mi tshovela ntshovelo wa rona, mi ta tisa ntsandza wa swilaveko swo sungula swa ku tshovela ka n’wina eka muprista;”' },
    { n: 11, text: '“U ta n’wan’wasela ntsandza mahlweni ka Yehovha leswaku wu amukeleka eka n’wina; hi siku ra le ndzhaku ka savata muprista u ta wu n’wan’wasela.”' },
    { n: 12, text: '“Hi siku leri mi n’wan’waselaka ntsandza, mi ta nyikela xinyimpfu xa xinuna xa lembe rin’we lexi nga riki na xilaveko, tanihi xitlhavelo xo hisiwa eka Yehovha.”' },
    { n: 13, text: '“Munyikelo wa xinkwa wa xona wu ta va swiyenge swimbirhi swa khume swa flour yo fuma leyi hanganisiweke ni mafurha, xitlhavelo xa ndzilo eka Yehovha xa nkhombo wa ku fuma; naswona munyikelo wa xonwa wa vhinyo wu ta va xiyenge xa mune xa hinyi.”' },
    { n: 14, text: '“Mi nga dyi xinkwa, kumbe mavele yo katingiwa, kumbe mavele yo basa, ku fikela hi siku leri mi tisaka munyikelo wa Xikwembu xa n’wina; i nawu lowu nga heriki eka tinxaka hinkwato ta n’wina emitiyeni ya n’wina hinkwayo.”' },
    { n: 15, text: '“Mi ta hlayela ku sukela hi siku ra le ndzhaku ka savata, ku sukela hi siku leri mi tiseke ntsandza wa munyikelo lowu n’wan’waseriweke; ku ta va ni tisavata ta ntlhanu na timbirhi leti heleleke;”' },
    { n: 16, text: '“Ku fikela hi siku ra le ndzhaku ka savata ya vunkombo mi ta hlayela masiku ya makume ya ntlhanu; endzhaku ka sweswo mi ta nyikela munyikelo wa xinkwa lowuntshwa eka Yehovha.”' },
    { n: 17, text: '“Mi ta humesa emitiyeni ya n’wina swinkwa swimbirhi swa munyikelo lowu n’wan’waseriweke, swa swiyenge swimbirhi swa khume swa flour yo fuma; swi ta pshatliwa na nchivirisi, tanihi swilaveko swo sungula eka Yehovha.”' },
    { n: 18, text: '“Kusuhi ni swinkwa sweswo, mi ta nyikela swinyimpfu swa ntlhanu na swimbirhi swa xinuna swa lembe rin’we leswi nga riki na xilaveko, ni xinkunzi xin’we xa ntsandza, ni tinhon’wana timbirhi ta xinuna; swi ta va xitlhavelo xo hisiwa eka Yehovha, ni munyikelo wa swinkwa wa swona ni minyikelo ya swona ya vhinyo, xitlhavelo xa ndzilo xa nkhombo wa ku fuma eka Yehovha.”' },
    { n: 19, text: '“Mi ta nyikela mbuti yin’we ya xinuna tanihi xitlhavelo xa xidyoho, ni swinyimpfu swimbirhi swa xinuna swa lembe rin’we tanihi xitlhavelo xa ku rhula.”' },
    { n: 20, text: '“Muprista u ta swi n’wan’wasela kusuhi ni swinkwa swa swilaveko swo sungula, mahlweni ka Yehovha, swi ta va leswo kwetsima eka Yehovha, hikwalaho ka muprista.”' },
    { n: 21, text: '“Hi siku rero mi ta tivisa nhlengeletano yo kwetsima eka n’wina; mi nga endli ntirho lowu bikiwaka hi nkhongolo; i nawu lowu nga heriki emitiyeni ya n’wina hinkwayo eka tinxaka hinkwato ta n’wina.”' },
    { n: 22, text: '“Loko mi tshovela ntshovelo wa tiko ra n’wina, u nga tsemi hinkwaswo ku fikela etlhelweni ra masin’wini ya wena, mi nga hlengeleti leswi seleke eku tshoveleni ka n’wina; u ta swi siyela xisiwana ni munhu wa matiko mambe; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 23, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 24, text: '“Vulavula ni vana va Israyele, u ku: Hi n’weti wa vunkombo, hi siku ro sungula ra n’weti, mi ta va ni ku wisanyana lokukulu, xitsundzuxo xa ku bajiwa ka timhalamhala, nhlengeletano yo kwetsima.”' },
    { n: 25, text: '“Mi nga endli ntirho lowu bikiwaka hi nkhongolo; mi ta nyikela xitlhavelo xa ndzilo eka Yehovha.”' },
    { n: 26, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 27, text: '“Kambe hi siku ra vukhume ra n’weti lowu wa vunkombo, i siku ra mukutsulo; ri ta va nhlengeletano yo kwetsima eka n’wina, mi ta xanisa mimoya ya n’wina, mi nyikela xitlhavelo xa ndzilo eka Yehovha.”' },
    { n: 28, text: '“Mi nga endli ntirho hambi wu ri wihi hi siku rero; hikuva i siku ra mukutsulo, leswaku mi endleriwa mukutsulo mahlweni ka Yehovha Xikwembu xa n’wina.”' },
    { n: 29, text: '“Hikuva un’wana ni un’wana loyi a nga xanisiki moya wa yena hi siku rero, u ta susiwa exikarhi ka vanhu va ka vona.”' },
    { n: 30, text: '“Un’wana ni un’wana loyi a endlaka ntirho hambi wu ri wihi hi siku rero, ndzi ta dlaya munhu yoloye exikarhi ka vanhu va ka vona.”' },
    { n: 31, text: '“Mi nga endli ntirho hambi wu ri wihi; i nawu lowu nga heriki eka tinxaka hinkwato ta n’wina emitiyeni ya n’wina hinkwayo.”' },
    { n: 32, text: '“Ri ta va savata ya ku wisanyana lokukulu eka n’wina, mi ta xanisa mimoya ya n’wina; hi siku ra vugendzi ra n’weti, hi nkarhi wa nimadyambu, ku sukela nimadyambu ku fikela nimadyambu ya le ndzhaku, mi ta hlayisa savata ya n’wina.”' },
    { n: 33, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 34, text: '“Vulavula ni vana va Israyele, u ku: Hi siku ra vukhume ni ntlhanu ra n’weti lowu wa vunkombo, i nkhuvo wa mitenda wa masiku ya ntlhanu na mambirhi eka Yehovha.”' },
    { n: 35, text: '“Hi siku ro sungula ku ta va ni nhlengeletano yo kwetsima; mi nga endli ntirho lowu bikiwaka hi nkhongolo.”' },
    { n: 36, text: '“Masiku ya ntlhanu na mambirhi mi ta nyikela xitlhavelo xa ndzilo eka Yehovha; hi siku ra vunkombo ku ta va ni nhlengeletano yo kwetsima eka n’wina, mi ta nyikela xitlhavelo xa ndzilo eka Yehovha; i nhlengeletano yo hlawuleka, mi nga endli ntirho lowu bikiwaka hi nkhongolo.”' },
    { n: 37, text: '“Leti hi tinsiku ta nkhuvo ta Yehovha, leti mi nga ta ti tivisa tanihi tinhlengeletano to kwetsima, leswaku mi nyikela xitlhavelo xa ndzilo eka Yehovha, xitlhavelo xo hisiwa, ni munyikelo wa xinkwa, ni xitlhavelo, ni minyikelo ya vhinyo, un’wana ni un’wana hi siku ra yena;”' },
    { n: 38, text: '“Kusuhi ni tisavata ta Yehovha, ni kusuhi ni tinyiko ta n’wina, ni kusuhi ni swikombelo hinkwaswo swa n’wina, ni kusuhi ni minyikelo ya n’wina hinkwayo ya ku tirhandzela, leyi mi yi nyikaka Yehovha.”' },
    { n: 39, text: '“Kambe hi siku ra vukhume ni ntlhanu ra n’weti wa vunkombo, loko mi hlengeleteke mihandzu ya tiko, mi ta endla nkhuvo wa Yehovha masiku ya ntlhanu na mambirhi; siku ro sungula ri ta va ra ku wisanyana, ni siku ra vunkombo ri ta va ra ku wisanyana.”' },
    { n: 40, text: '“Hi siku ro sungula mi ta teka mihandzu ya miri ya ku saseka, ni mahala ya masinya ya nindza, ni marhavi ya masinya ya ku fuma, ni marhavi ya masinya ya milambu, mi tsaka mahlweni ka Yehovha Xikwembu xa n’wina masiku ya ntlhanu na mambirhi.”' },
    { n: 41, text: '“Mi ta endla nkhuvo lowu eka Yehovha masiku ya ntlhanu na mambirhi hi lembe; i nawu lowu nga heriki eka tinxaka hinkwato ta n’wina; mi ta wu endla hi n’weti wa vunkombo.”' },
    { n: 42, text: '“Mi ta tshama emitendeni masiku ya ntlhanu na mambirhi; un’wana ni un’wana loyi a tswariweke eIsrayele u ta tshama emitendeni;”' },
    { n: 43, text: '“Leswaku tinxaka ta n’wina ti tiva leswaku ndzi tshamise vana va Israyele emitendeni, loko ndzi va humese etikweni ra Egipta; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 44, text: 'Moxe a byela vana va Israyele tinsiku ta nkhuvo ta Yehovha.' }
  ],
  24: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Lerisa vana va Israyele leswaku va ku tisela mafurha yo tengama ya mahlwari lama pshatliweke, ya rivoni, leswaku rivoni ri tshama ri pfurha nkarhi hinkwawo.”' },
    { n: 3, text: '“Etlhelweni ra xiyenge xa vumbhoni, eka tabernakela ya nhlanganiso, Aroni u ta ri hlela ku sukela nimadyambu ku fikela nimixo mahlweni ka Yehovha; i nawu lowu nga heriki eka tinxaka hinkwato ta n’wina.”' },
    { n: 4, text: '“U ta hlela mavoni eka xo tlhoma mavoni xo tengama mahlweni ka Yehovha nkarhi hinkwawo.”' },
    { n: 5, text: '“U ta teka flour yo fuma, u baka swinkwa swa khume na swimbirhi hi yona; swiyenge swimbirhi swa khume swi ta va eka xinkwa xin’wana ni xin’wana.”' },
    { n: 6, text: '“U ta swi veka hi tinxaka timbirhi, swa tsevu eka nxaka yin’wana ni yin’wana, ehenhla ka tafula ro tengama mahlweni ka Yehovha.”' },
    { n: 7, text: '“U ta chela incense yo tengama eka nxaka yin’wana ni yin’wana, leswaku yi va eka swinkwa tanihi xitsundzuxo, xitlhavelo xa ndzilo eka Yehovha.”' },
    { n: 8, text: '“Siku rin’we ni rin’we ra savata u ta swi hlela mahlweni ka Yehovha nkarhi hinkwawo; i ntwanano lowu nga heriki lowu humaka eka vana va Israyele.”' },
    { n: 9, text: '“Swi ta va swa Aroni ni vana va yena, va ta swi dyela endhawini yo kwetsima; hikuva i nchumu lowo kwetsima swinene eka yena, lowu humaka eka switlhavelo swa ndzilo swa Yehovha, tanihi nawu lowu nga heriki.”' },
    { n: 10, text: '“N’wana wa wansati wa Muisrayele, loyi tata wa yena a a ri Muegipta, u humele exikarhi ka vana va Israyele; naswona n’wana loyi wa wansati wa Muisrayele ni wanuna wa Muisrayele va lwile ekampeni;”' },
    { n: 11, text: '“N’wana wa wansati wa Muisrayele u rhukanile vito ra Yehovha, a ri sandza; va n’wi tisa eka Moxe. Vito ra mana wa yena a a ri Xelomiti, n’wana wa Dibri, wa nyimba ya Dani.”' },
    { n: 12, text: '“Va n’wi veka ekhotsweni, ku fikela loko va tiva rito ra Yehovha.”' },
    { n: 13, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 14, text: '“Humesa munhu la rhukaneke ehandle ka kampa; hinkwavo lava n’wi tweke va ta veka mavoko ya vona enhlokweni ya yena, naswona nhlengeletano hinkwayo yi ta n’wi ba hi maribye.”' },
    { n: 15, text: '“U ta vulavula ni vana va Israyele, u ku: Un’wana ni un’wana la rhukanaka Xikwembu xa yena u ta rhwala xidyoho xa yena.”' },
    { n: 16, text: '“Loyi a sandzaka vito ra Yehovha u ta dlayiwa; nhlengeletano hinkwayo yi ta n’wi ba hi maribye; hambi a ri munhu wa matiko mambe kumbe munhu wa tiko, loko a sandza vito ra Yehovha, u ta dlayiwa.”' },
    { n: 17, text: '“Wanuna loyi a dlayaka munhu wihi na wihi, u ta dlayiwa.”' },
    { n: 18, text: '“Loyi a dlayaka xifuwo u ta xi riha, vutomi hi vutomi.”' },
    { n: 19, text: '“Loko munhu a vangela munhu wa ka vona vurema, hilaha a endleke hakona, na yena u ta endliwa sweswo;”' },
    { n: 20, text: '“Ku pshatleka hi ku pshatleka, tihlo hi tihlo, tinyo hi tinyo; hilaha a vangeleke munhu yoloye vurema, na yena u ta endliwa sweswo.”' },
    { n: 21, text: '“Loyi a dlayaka xifuwo u ta xi riha; kambe loyi a dlayaka munhu u ta dlayiwa.”' },
    { n: 22, text: '“Mi ta va ni nawu wun’we, hambi a ri munhu wa matiko mambe, hambi a ri munhu wa tiko; hikuva hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 23, text: 'Moxe a vulavula ni vana va Israyele; va humesa munhu la rhukaneke ehandle ka kampa, va n’wi ba hi maribye. Vana va Israyele va endla hilaha Yehovha a leriseke Moxe hakona.' }
  ],
  25: [
    { n: 1, text: 'Yehovha a vulavula na Moxe entshaveni ya Sinayi, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko mi nghena etikweni leri ndzi mi nyikaka rona, tiko ri ta hlayisa savata eka Yehovha.”' },
    { n: 3, text: '“Tsevu wa malembe u ta byala nsimu ya wena, tsevu wa malembe u ta tsema miri ya wena ya vhinya, u hlengeleta mihandzu ya tiko;”' },
    { n: 4, text: '“Kambe hi lembe ra vunkombo ku ta va ni savata ya ku wisanyana eka tiko, savata ya Yehovha; u nga byali nsimu ya wena, mi nga tsemi miri ya wena ya vhinya.”' },
    { n: 5, text: '“Leswi milaka hi swoxe endzhaku ka ntshovelo wa wena u nga swi tsemi, ni mihandzu ya miri ya wena leyi nga tsemiwangiki u nga yi hlengeleti; ri ta va lembe ra ku wisanyana eka tiko.”' },
    { n: 6, text: '“Savata ya tiko yi ta va swakudya swa n’wina: eka wena, ni xitirhi xa wena, ni nandza wa wena wa xisati, ni nandza wa wena wa xinuna, ni munhu wa matiko mambe loyi a tshamaka na wena;”' },
    { n: 7, text: '“Ni swifuwo swa wena, ni swivandzana leswi nga etikweni ra wena, hinkwaswo swakudya swa yona swi ta dya swona.”' },
    { n: 8, text: '“U ta hlayela tisavata ta ntlhanu na timbirhi ta malembe, malembe ya ntlhanu na mambirhi hi makhume ya ntlhanu na mambirhi; naswona masiku ya tisavata ta ntlhanu na timbirhi ta malembe ya ta va malembe ya makhume ya mune ni kaye.”' },
    { n: 9, text: '“Endzhaku ka sweswo u ta tivisa mpfumawulo wa mhalampala hi siku ra vukhume ra n’weti wa vunkombo; hi siku ra mukutsulo mi ta yisa mpfumawulo wa mhalampala etikweni ra n’wina hinkwaro.”' },
    { n: 10, text: '“Mi ta kwetsimisa lembe ra vumakhume ya ntlhanu, mi tivisa ku ntsunxeka etikweni hinkwaro eka hinkwavo lava tshamaka eka rona; ri ta va Yubile eka n’wina; un’wana ni un’wana wa n’wina u ta tlhelela eka ndzhaka ya yena, naswona un’wana ni un’wana u ta tlhelela endyangwini wa yena.”' },
    { n: 11, text: '“Lembe rero ra vumakhume ya ntlhanu ri ta va Yubile eka n’wina; mi nga byali, mi nga tsemi leswi milaka hi swoxe eka rona, mi nga hlengeleti mihandzu ya masinya ya vhinya yo kala ku tsemiwa.”' },
    { n: 12, text: '“Hikuva i Yubile; ri ta va ro kwetsima eka n’wina; mi ta dya mihandzu ya rona leyi humaka ensin’wini.”' },
    { n: 13, text: '“Hi lembe leri ra Yubile un’wana ni un’wana wa n’wina u ta tlhelela eka ndzhaka ya yena.”' },
    { n: 14, text: '“Loko mi xavisa nchumu eka munhu wa n’wina, kumbe mi xava emavokweni ya munhu wa n’wina, mi nga kanganyisani;”' },
    { n: 15, text: '“U ta xava eka munhu wa wena hi ku landza nhlayo ya malembe ya le ndzhaku ka Yubile; na yena u ta xavisa eka wena hi ku landza nhlayo ya malembe ya ntshovelo.”' },
    { n: 16, text: '“Hi ku landza ku tala ka malembe u ta engetela ntsengo wa rona, naswona hi ku landza ku hunguteka ka malembe u ta hunguta ntsengo wa rona; hikuva u xavisa eka wena nhlayo ya mintshovelo.”' },
    { n: 17, text: '“Mi nga kanganyisani, kambe mi ta chava Xikwembu xa n’wina; hikuva hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 18, text: '“Hikwalaho mi ta endla milawu ya mina, mi hlayisa swileriso swa mina, mi swi endla, leswaku mi tshama etikweni mi sirhelelekile.”' },
    { n: 19, text: '“Tiko ri ta humesa mihandzu ya rona, mi ta dya mi xurha, naswona mi ta tshama eka rona mi sirhelelekile.”' },
    { n: 20, text: '“Loko mi ku: ‘Xana hi ta dya yini hi lembe ra vunkombo, hikuva hi nga byali, naswona hi nga hlengeleti mihandzu ya hina?’”' },
    { n: 21, text: '“Ndzi ta mi rhumela mikateko ya mina hi lembe ra vutsevu, naswona ri ta humesa mihandzu ya malembe manharhu.”' },
    { n: 22, text: '“Hi lembe ra vunhungu mi ta byala, kambe mi ta dya eka mihandzu ya khale ku fikela hi lembe ra vukaye; ku fikela loko mihandzu ya rona yi tisiwa, mi ta dya ya khale.”' },
    { n: 23, text: '“Tiko a ri nge xavisiwi hi ku helela; hikuva tiko i ra mina, hikuva mi vahlaluki ni vaendzi eka mina.”' },
    { n: 24, text: '“Etikweni hinkwaro ra ndzhaka ya n’wina mi ta pfumelela ku kutsuriwa ka tiko.”' },
    { n: 25, text: '“Loko makwenu a ri xisiwana, a xavisa xiphemu xa ndzhaka ya yena, mukutsuri wa yena la tshineleke u ta ta a kutsula leswi makwenu a swi xaviseke.”' },
    { n: 26, text: '“Loko munhu a nga ri na mukutsuri, kambe voko ra yena ri kuma ndlela yo ri kutsula hi rona;”' },
    { n: 27, text: '“U ta hlayela malembe ya ku xavisiwa ka rona, a tlherisela ntsengo lowu saleke eka wanuna loyi a n’wi xaviseleke rona, a tlhelela eka ndzhaka ya yena.”' },
    { n: 28, text: '“Kambe loko voko ra yena ri nga kumi ndlela yo tlherisela ntsengo lowu, leswi xavisiweke swi ta tshama evokweni ra loyi a swi xaveke ku fikela hi lembe ra Yubile; hi lembe ra Yubile swi ta huma, naswona u ta tlhelela eka ndzhaka ya yena.”' },
    { n: 29, text: '“Loko munhu a xavisa yindlu yo tshama eka yona emutini lowu nga ni makhumbi, u ta va ni mfanelo yo yi kutsula ku fikela loko lembe ri hela ku sukela loko yi xavisiwile; mfanelo ya yena yo kutsula yi ta tshama lembe hinkwaro.”' },
    { n: 30, text: '“Kambe loko yi nga kutsuriwanga ku fikela loko lembe ri helela, yindlu leyi nga emutini lowu nga ni makhumbi yi ta tshama yi ri ya loyi a yi xaveke ni ya tinxaka ta yena hi ku helela; a yi nge humi hi lembe ra Yubile.”' },
    { n: 31, text: '“Kambe tiyindlu ta swimitana leswi nga riki na makhumbi ti ta hlayiwa kusuhi ni masimu ya tiko; ti ta va ni mfanelo yo kutsuriwa, naswona ti ta huma hi lembe ra Yubile.”' },
    { n: 32, text: '“Kambe emitingwini ya Valevi, tiyindlu ta miti ya ndzhaka ya vona, Valevi va ta va ni mfanelo yo ti kutsula nkarhi hinkwawo.”' },
    { n: 33, text: '“Loko munhu a kutsula eka Valevi, yindlu leyi xavisiweke emutini wa ndzhaka ya vona yi ta huma hi lembe ra Yubile; hikuva tiyindlu ta miti ya Valevi i ndzhaka ya vona exikarhi ka vana va Israyele.”' },
    { n: 34, text: '“Kambe nsimu ya madyelo ya miti ya vona a yi nge xavisiwi; hikuva i ndzhaka ya vona ya hilaha ku nga heriki.”' },
    { n: 35, text: '“Loko makwenu a ri xisiwana, naswona voko ra yena ri tsandzeka mahlweni ka wena, u ta n’wi pfuna, hambi a ri muhlaluhi kumbe muendzi, leswaku a tshama na wena.”' },
    { n: 36, text: '“U nga teki vutshelo kumbe ntsengo lowu engetelekeke eka yena, kambe u ta chava Xikwembu xa wena, leswaku makwenu a tshama na wena.”' },
    { n: 37, text: '“U nga n’wi nyiki mali ya wena hi vutshelo, naswona u nga n’wi nyiki swakudya swa wena hi ntsengo lowu engetelekeke.”' },
    { n: 38, text: '“Hi mina Yehovha Xikwembu xa n’wina, loyi a mi humeseke etikweni ra Egipta, leswaku ndzi mi nyika tiko ra Kanana, ndzi va Xikwembu xa n’wina.”' },
    { n: 39, text: '“Loko makwenu a ri xisiwana mahlweni ka wena, a tixavisa eka wena, u nga n’wi tirhisi ntirho wa nandza;”' },
    { n: 40, text: '“U ta tshama na wena tanihi xitirhi kumbe muendzi; u ta ku tirhela ku fikela hi lembe ra Yubile.”' },
    { n: 41, text: '“Endzhaku ka sweswo u ta huma mahlweni ka wena, yena ni vana va yena, a tlhelela endyangwini wa yena, a tlhelela eka ndzhaka ya vatata wa yena.”' },
    { n: 42, text: '“Hikuva i malandza ya mina, lawa ndzi ma humeseke etikweni ra Egipta; va nga xavisiwi hilaha va xavisaka malandza hakona.”' },
    { n: 43, text: '“U nga n’wi tirhisi hi vukarhi, kambe u ta chava Xikwembu xa wena.”' },
    { n: 44, text: '“Malandza ya wena ya xinuna ni ya xisati, lawa u nga ta va na wona, ya ta huma ematikweni lawa ma mi rhendzeleke; eka wona mi ta xava malandza ya xinuna ni ya xisati.”' },
    { n: 45, text: '“Naswona eka vana va vaendzi lava tshamaka na n’wina, eka vona mi ta xava, ni le ka mindyangu ya vona leyi nga na n’wina, leyi va yi tswaleke etikweni ra n’wina, va ta va ndzhaka ya n’wina.”' },
    { n: 46, text: '“Mi ta va endla ndzhaka eka vana va n’wina va le ndzhaku ka n’wina, leswaku va va ndzhaka ya n’wina hilaha ku nga heriki; mi ta va tirhisa; kambe eka vamakwenu vana va Israyele, un’wana ni un’wana u nga tirhisi makwenu hi vukarhi.”' },
    { n: 47, text: '“Loko muhlaluhi kumbe muendzi a humelela hi ku rhuva mahlweni ka wena, naswona makwenu a ri xisiwana mahlweni ka yena, a tixavisa eka muhlaluhi kumbe muendzi loyi a tshamaka na wena, kumbe eka n’wana wa ndyangu wa muhlaluhi;”' },
    { n: 48, text: '“Endzhaku ka ku tixavisa ka yena u ta va ni mfanelo yo kutsuriwa; un’wana wa vamakwenu u ta n’wi kutsula;”' },
    { n: 49, text: '“Kumbe makwenu wa tata wa yena, kumbe n’wana wa makwenu wa tata wa yena u ta n’wi kutsula, kumbe un’wana la tshineleke wa ndyangu wa yena u ta n’wi kutsula; kumbe, loko voko ra yena ri kuma ndlela, na yena u ta ti kutsula.”' },
    { n: 50, text: '“U ta hlayela ni loyi a n’wi xaveke, ku sukela hi lembe leri a tixaviseke ha rona ku fikela hi lembe ra Yubile; ntsengo wa ku tixavisa ka yena wu ta va hi ku landza nhlayo ya malembe, tanihi masiku ya xitirhi.”' },
    { n: 51, text: '“Loko ku sale malembe yo tala, u ta tlherisela ntsengo wa mukutsulo wa yena hi ku landza wona, eka mali leyi a xaviweke ha yona.”' },
    { n: 52, text: '“Loko ku sale malembe matsongo ku fikela hi lembe ra Yubile, u ta hlayela na yena; hi ku landza malembe ya yena u ta tlherisela ntsengo wa mukutsulo wa yena.”' },
    { n: 53, text: '“U ta tshama na yena tanihi xitirhi lembe ni lembe; a nga n’wi tirhisi hi vukarhi mahlweni ka mahlo ya wena.”' },
    { n: 54, text: '“Loko a nga kutsuriwanga hi tindlela leti, u ta huma hi lembe ra Yubile, yena ni vana va yena.”' },
    { n: 55, text: '“Hikuva vana va Israyele i malandza eka mina; i malandza ya mina lawa ndzi ma humeseke etikweni ra Egipta; hi mina Yehovha Xikwembu xa n’wina.”' }
  ],
  26: [
    { n: 1, text: '“Mi nga tiendli swikwembu swa hava, mi nga tiendli xifaniso lexi vatliweke kumbe jasi ra ribye, mi nga veki ribye leri tsemiweke etikweni ra n’wina leswaku mi nkhinsama mahlweni ka rona; hikuva hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 2, text: '“Mi ta hlayisa tisavata ta mina, mi xixima yindlu ya mina yo kwetsima; hi mina Yehovha.”' },
    { n: 3, text: '“Loko mi famba hi milawu ya mina, mi hlayisa swileriso swa mina, mi swi endla;”' },
    { n: 4, text: '“Ndzi ta mi nyika mpfula hi nkarhi wa yona, tiko ri ta humesa mihandzu ya rona, masinya ya masin’wini ya ta humesa mihandzu ya wona.”' },
    { n: 5, text: '“Ku hula ka n’wina ku ta fika eku tshoveleni ka vhinyo, naswona ku tshovela ka vhinyo ku ta fika eku byariweni; mi ta dya swakudya swa n’wina mi xurha, naswona mi ta tshama etikweni ra n’wina mi sirhelelekile.”' },
    { n: 6, text: '“Ndzi ta nyika ku rhula etikweni, mi ta etlela naswona a ku na loyi a nga ta mi chavisa; ndzi ta herisa swivandzana swo biha etikweni, naswona banga a ri nge hundzi etikweni ra n’wina.”' },
    { n: 7, text: '“Mi ta hlongola valala va n’wina, va ta wa mahlweni ka n’wina hi banga.”' },
    { n: 8, text: '“Ntlhanu wa n’wina u ta hlongola lava makhume ya ntlhanu, naswona lava makhume ya ntlhanu va n’wina va ta hlongola lava khume ra magidi; valala va n’wina va ta wa mahlweni ka n’wina hi banga.”' },
    { n: 9, text: '“Ndzi ta mi languta, ndzi mi endla mi tswalana, ndzi mi andzisa, naswona ndzi ta tiyisa ntwanano wa mina na n’wina.”' },
    { n: 10, text: '“Mi ta dya swakudya swa khale leswi tshiweke nkarhi wo leha, naswona mi ta humesa swa khale mahlweni ka leswintshwa.”' },
    { n: 11, text: '“Ndzi ta veka tabernakela ya mina exikarhi ka n’wina, naswona moya wa mina a wu nge mi vengi.”' },
    { n: 12, text: '“Ndzi ta famba exikarhi ka n’wina, ndzi va Xikwembu xa n’wina, naswona mi ta va vanhu va mina.”' },
    { n: 13, text: '“Hi mina Yehovha Xikwembu xa n’wina, loyi a mi humeseke etikweni ra Egipta leswaku mi nga vi malandza ya vona; ndzi tshovele joko ra n’wina, ndzi mi endla mi famba mi lulamile.”' },
    { n: 14, text: '“Kambe loko mi nga ndzi yingisi, mi nga endli swileriso leswi hinkwaswo;”' },
    { n: 15, text: '“Loko mi venga milawu ya mina, naswona moya wa n’wina wu venga swileriso swa mina, mi nga endli swileriso hinkwaswo swa mina, mi tshova ntwanano wa mina;”' },
    { n: 16, text: '“Na mina ndzi ta mi endla leswi: Ndzi ta mi rhumela khombo, vuvabyi bya ku tshama ni vuvabyi bya nhloko, leswi nga ta herisa mahlo, swi tisa gome emoyeni; mi ta byara mbewu ya n’wina mahala, hikuva valala va n’wina va ta yi dya.”' },
    { n: 17, text: '“Ndzi ta lwisana ni n’wina, mi ta biwa mahlweni ka valala va n’wina; lava mi vengaka va ta mi fuma, naswona mi ta tsutsuma ku nga ri na loyi a mi hlongolaka.”' },
    { n: 18, text: '“Loko endzhaku ka swilo leswi hinkwaswo mi nga ndzi yingisi, ndzi ta mi laya ka ntlhanu na kambirhi hikwalaho ka swidyoho vya n’wina.”' },
    { n: 19, text: '“Ndzi ta tshova ku tikurisa ka matimba ya n’wina; ndzi ta endla tilo ra n’wina ri fana ni nsimbi, ni misava ya n’wina yi fana ni ntsumbula;”' },
    { n: 20, text: '“Matimba ya n’wina ya ta hela mahala, hikuva tiko ra n’wina a ri nge humesi mihandzu ya rona, ni masinya ya tiko a ma nge humesi mihandzu ya wona.”' },
    { n: 21, text: '“Loko mi famba hi ku lwisana na mina, mi nga pfumeli ku ndzi yingisi, ndzi ta mi engetela mitsalo ka ntlhanu na kambirhi hikwalaho ka swidyoho vya n’wina.”' },
    { n: 22, text: '“Ndzi ta mi rhumela swivandzana swa nhova, leswi nga ta mi tekela vana va n’wina, swi dlaya swifuwo swa n’wina, swi hunguta nhlayo ya n’wina, naswona tindlela ta n’wina ti ta va masaka.”' },
    { n: 23, text: '“Loko hi swilo leswi hinkwaswo mi nga pfumeli ku liyiwa hi mina, kambe mi famba hi ku lwisana na mina;”' },
    { n: 24, text: '“Na mina ndzi ta famba hi ku lwisana na n’wina, ndzi mi ba, ina, mina, ka ntlhanu na kambirhi hikwalaho ka swidyoho vya n’wina.”' },
    { n: 25, text: '“Ndzi ta mi tisa banga leri nga ta rihisela ku tshoveka ka ntwanano; loko mi hlengeletana emitingwini ya n’wina, ndzi ta mi rhumela ntungu exikarhi ka n’wina, mi ta nyikeriwa evokweni ra nala.”' },
    { n: 26, text: '“Loko ndzi tshovele ntsandza wa xinkwa xa n’wina, vavasati va khume va ta baka swinkwa swa n’wina pakeni yin’we, va ta mi tlherisela swinkwa swa n’wina hi xipimo; mi ta dya, kambe mi nga xurhi.”' },
    { n: 27, text: '“Loko hi sweswo mi nga ndzi yingisi, kambe mi famba hi ku lwisana na mina;”' },
    { n: 28, text: '“Ndzi ta famba hi ku lwisana na n’wina hi vukarhi bya ntiyiso, na mina ndzi ta mi laya ka ntlhanu na kambirhi hikwalaho ka swidyoho vya n’wina.”' },
    { n: 29, text: '“Mi ta dya nyama ya vana va n’wina va xinuna, ni nyama ya vana va n’wina va xisati mi ta yi dya.”' },
    { n: 30, text: '“Ndzi ta herisa tindhawu ta n’wina leti tlakukeke, ndzi herisa swifaniso swa n’wina swa incense, ndzi lahla mintsumbu ya n’wina ehenhla ka mintsumbu ya swikwembu swa n’wina swa hava; naswona moya wa mina wu ta mi venga.”' },
    { n: 31, text: '“Ndzi ta endla miti ya n’wina masaka, ndzi endla tindhawu ta n’wina to kwetsima ti va tinini, naswona a ndzi nge nuhweli nkhombo wa ku fuma wa n’wina.”' },
    { n: 32, text: '“Ndzi ta endla tiko ri va leri hovotsaka, naswona valala va n’wina lava tshamaka eka rona va ta hlamala ha rona.”' },
    { n: 33, text: '“Ndzi ta mi hangalasa exikarhi ka matiko, ndzi pfula banga endzhaku ka n’wina; tiko ra n’wina ri ta va leri hovotsaka, naswona miti ya n’wina yi ta va masaka.”' },
    { n: 34, text: '“Hi nkarhi woloyo tiko ri ta hlayisa tisavata ta rona, masiku hinkwaswo ya ku va leri hovotsaka, loko mi ri etikweni ra valala va n’wina; hi nkarhi woloyo tiko ri ta wisa, ri hlayisa tisavata ta rona.”' },
    { n: 35, text: '“Masiku hinkwaswo ya ku va leri hovotsaka ri ta wisa, leswi ri nga wisangiki hi tisavata ta n’wina, loko mi tshamile eka rona.”' },
    { n: 36, text: '“Eka lava va nga ta sala eka n’wina, ndzi ta chela vutoya emimbilwini ya vona ematikweni ra valala va vona; mpfumawulo wa tluka leri hungiweke wu ta va tsutsumisa, va ta tsutsuma tanihi loko va tsutsuma banga, va wa ku nga ri na loyi a va hlongolaka.”' },
    { n: 37, text: '“Va ta wa un’wana ehenhla ka un’wana, tanihi mahlweni ka banga, ku nga ri na loyi a va hlongolaka; mi nga nge vi na matimba yo yima mahlweni ka valala va n’wina.”' },
    { n: 38, text: '“Mi ta lahleka exikarhi ka matiko, naswona tiko ra valala va n’wina ri ta mi dya.”' },
    { n: 39, text: '“Lava va nga ta sala eka n’wina va ta herisiwa hikwalaho ka vuhomboloki bya vona ematikweni ra valala va n’wina; naswona hikwalaho ka vuhomboloki bya vatata wa vona va ta herisiwa na vona.”' },
    { n: 40, text: '“Va ta tivula vuhomboloki bya vona, ni vuhomboloki bya vatata wa vona, eka ku nga tshembeki leri va endleke ha rona eka mina, naswona hikuva va fambile hi ku lwisana na mina;”' },
    { n: 41, text: '“Na mina ndzi fambile hi ku lwisana na vona, ndzi va tisa etikweni ra valala va vona; loko timbilu ta vona leti nga yimbisiwangiki ti titsongahata, naswona va amukela mukutsulo wa vuhomboloki bya vona;”' },
    { n: 42, text: '“Ndzi ta tsundzuka ntwanano wa mina na Yakobo, ni ntwanano wa mina na Isaka, ni ntwanano wa mina na Abrahama ndzi ta wu tsundzuka; naswona ndzi ta tsundzuka tiko.”' },
    { n: 43, text: '“Tiko ri ta siyiwa hi vona, ri hlayisa tisavata ta rona loko ri ri leri hovotsaka handle ka vona; va ta amukela mukutsulo wa vuhomboloki bya vona, hikuva, ina, hikuva va vengi swileriso swa mina, naswona moya wa vona wu vengi milawu ya mina.”' },
    { n: 44, text: '“Kambe hambi swi ri tano, loko va ri etikweni ra valala va vona, a ndzi nge va lahli, naswona a ndzi nge va vengi ku fikela eku va heriseni hi ku helela, ndzi tshova ntwanano wa mina na vona; hikuva hi mina Yehovha Xikwembu xa vona.”' },
    { n: 45, text: '“Kambe hikwalaho ka vona ndzi ta tsundzuka ntwanano wa khale, lowu ndzi va humeseke etikweni ra Egipta mahlweni ka matiko hinkwaswo, leswaku ndzi va Xikwembu xa vona; hi mina Yehovha.”' },
    { n: 46, text: '“Lawa hi wona milawu, ni swileriso, ni tinawu leti Yehovha a ti veke exikarhi ka yena ni vana va Israyele entshaveni ya Sinayi, hi voko ra Moxe.”' }
  ],
27: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko munhu a endla xihlambanyo xo hlawuleka xa ntsengo eka Yehovha hikwalaho ka vanhu;”' },
    { n: 3, text: '“Ntsengo wa xinuna ku sukela eka malembe ya makume mambirhi ku fikela eka malembe ya makhume tsevu, ntsengo wa wena wu ta va makhume ya ntlhanu ya tixekele ta silivhere, hi xipimo xa vukwetsimi.”' },
    { n: 4, text: '“Loko a ri wansati, ntsengo wa wena wu ta va makhume manharhu ya tixekele.”' },
    { n: 5, text: '“Ku sukela eka malembe ya ntlhanu ku fikela eka malembe ya makume mambirhi, ntsengo wa xinuna wu ta va makhume mambirhi ya tixekele, naswona wa wansati wu ta va khume ra tixekele.”' },
    { n: 6, text: '“Ku sukela eka n’weti un’we ku fikela eka malembe ya ntlhanu, ntsengo wa xinuna wu ta va ntlhanu wa tixekele ta silivhere, naswona ntsengo wa wansati wu ta va tixekele tinharhu ta silivhere.”' },
    { n: 7, text: '“Ku sukela eka malembe ya makhume tsevu na ku tlhandlaka, loko a ri xinuna ntsengo wu ta va khume na ntlhanu wa tixekele, naswona loko a ri wansati wu ta va khume ra tixekele.”' },
    { n: 8, text: '“Kambe loko a ri xisiwana swinene lerova a nga swi koti ku hakelela ntsengo wa wena, u ta yisiwa mahlweni ka muprista, naswona muprista u ta n’wi nyika ntsengo; muprista u ta n’wi nyika ntsengo hi ku landza leswi loyi a tshembiseke a nga swi kotaka.”' },
    { n: 9, text: '“Loko ku ri xifuwo lexi va nga xi nyikelaka tanihi munyikelo eka Yehovha, hinkwaswo leswi un’wana a swi nyikaka Yehovha swi ta va leswo kwetsima.”' },
    { n: 10, text: '“A nga fanelanga ku xi cinca, hambi ku ri ku nyika lexi nga ni vuvabyi ematshan’wini ya lexi tengeke, kumbe lexi tengeke ematshan’wini ya lexi nga ni vuvabyi; loko o tshuka a cincile xifuwo hi xifuwo xin’wana, xeswo ni xeswiya lexi cinciweke swi ta va leswo kwetsima.”' },
    { n: 11, text: '“Loko ku ri xifuwo lexi nga tengangiki, lexi va nga fanelangiki ku xi nyikela tanihi munyikelo eka Yehovha, u ta yisa xifuwo xeswo mahlweni ka muprista;”' },
    { n: 12, text: '“Naswona muprista u ta xi nyika ntsengo, hambi xi ri lexi tengeke kumbe lexi nga tengangiki; hilaha muprista, ntsengo wa wena, a xi vekaka hakona, swi ta va tano.”' },
    { n: 13, text: '“Kambe loko a swi lava hakunene ku xi kutsula, u ta engetela xiyenge xa ntlhanu eka ntsengo wa wena.”' },
    { n: 14, text: '“Loko munhu a hlawula yindlu ya yena leswaku yi va yo kwetsima eka Yehovha, muprista u ta yi nyika ntsengo, hambi yi ri leyinene kumbe leyi nga riki yinene; hilaha muprista a yi vekaka hakona, swi ta yima tano.”' },
    { n: 15, text: '“Loko loyi a yi hlawuleke a lava ku kutsula yindlu ya yena, u ta engetela xiyenge xa ntlhanu xa mali ya ntsengo wa wena eka yona, naswona yi ta va ya yena.”' },
    { n: 16, text: '“Loko munhu a hlawula xiphemu xa nsimu ya ndzhaka ya yena eka Yehovha, ntsengo wa wena wu ta va hi ku landza mbewu ya yona; nsimu leyi byariwaka hi homeri ya mbewu ya maxalana yi ta va makhume ya ntlhanu ya tixekele ta silivhere.”' },
    { n: 17, text: '“Loko a hlawula nsimu ya yena ku sukela hi lembe ra Yubile, yi ta yima hi ku landza ntsengo wa wena hinkwaro.”' },
    { n: 18, text: '“Kambe loko a hlawula nsimu ya yena endzhaku ka Yubile, muprista u ta hlayela mali eka yena hi ku landza malembe lama saleke ku fikela eka lembe ra Yubile leri landzelaka, naswona ntsengo wa wena wu ta hunguteka.”' },
    { n: 19, text: '“Loko loyi a hlawuleke nsimu a lava hakunene ku yi kutsula, u ta engetela xiyenge xa ntlhanu xa mali ya ntsengo wa wena eka yona, naswona yi ta va ya yena.”' },
    { n: 20, text: '“Loko a nga yi kutsuli nsimu, kumbe loko a xavisele munhu un’wana nsimu, a yi nge he kutsuriwi;”' },
    { n: 21, text: '“Kambe nsimu leyi, loko yi huma hi lembe ra Yubile, yi ta va yo kwetsima eka Yehovha, tanihi nsimu leyi nyikeriweke hi ku helela; yi ta va ndzhaka ya muprista.”' },
    { n: 22, text: '“Loko a hlawula nsimu leyi a yi xaveke eka Yehovha, leyi nga riki xiphemu xa masimu ya ndzhaka ya yena;”' },
    { n: 23, text: '“Muprista u ta hlayela ntsengo wa wena ku fikela hi lembe ra Yubile; naswona u ta nyika ntsengo wa wena hi siku rero, tanihi nchumu lowu kwetsimaka eka Yehovha.”' },
    { n: 24, text: '“Hi lembe ra Yubile nsimu yi ta tlhelela eka loyi a yi xaveke eka yena, eka loyi tiko ri nga ra yena tanihi ndzhaka.”' },
    { n: 25, text: '“Naswona ntsengo wa wena hinkwaro wu ta va hi xipimo xa vukwetsimi; tixekele ta makume mambirhi ti ta va gera yin’we.”' },
    { n: 26, text: '“Kambe mativula exikarhi ka swifuwo, lawa ya nga ya Yehovha tanihi mativula, a ku na munhu loyi a nga ma hlawulaka; hambi xi ri xinkunzi, kumbe xinyimpfu, i ya Yehovha.”' },
    { n: 27, text: '“Loko ku ri xifuwo lexi nga tengangiki, u ta xi kutsula hi ku landza ntsengo wa wena, u engetela xiyenge xa ntlhanu eka wona; naswona loko xi nga kutsuriwi, xi ta xavisiwa hi ku landza ntsengo wa wena.”' },
    { n: 28, text: '“Kambe a ku na nchumu lowu nyikeriweke hi ku helela lowu munhu a nga na wona, lowu a nga wu nyikela eka Yehovha, hambi a ri munhu, kumbe xifuwo, kumbe nsimu ya ndzhaka ya yena, lowu nga xavisiwaka kumbe ku kutsuriwa; nchumu hinkwaro lowu nyikeriweke hi ku helela i lowo kwetsima swinene eka Yehovha.”' },
    { n: 29, text: '“A ku na munhu loyi a nyikeriweke hi ku helela, loyi a dlayiweke exikarhi ka vanhu, loyi a nga kutsuriwaka; u ta dlayiwa hakunene.”' },
    { n: 30, text: '“Naswona vukhume hinkwaro bya tiko, hambi ku ri mbewu ya tiko, kumbe mihandzu ya miri, i swa Yehovha; i swo kwetsima eka Yehovha.”' },
    { n: 31, text: '“Loko munhu a lava hakunene ku kutsula xiphemu xa vukhume bya yena, u ta engetela xiyenge xa ntlhanu eka byona.”' },
    { n: 32, text: '“Naswona eka vukhume bya swifuwo swa tihomu ni swinyimpfu, hinkwaswo leswi hundzaka ehansi ka nhonga, nchumu wa vukhume wu ta va wo kwetsima eka Yehovha.”' },
    { n: 33, text: '“A nga fanelanga ku hlawula hambi i xinene kumbe xo biha, naswona a nga fanelanga ku xi cinca; loko o tshuka a xi cincile hakunene, xeswo ni xeswiya lexi cinciweke swi ta va leswo kwetsima, a swi nge kutsuriwi.”' },
    { n: 34, text: '“Lawa hi wona swileriso leswi Yehovha a swi nyikeke Moxe hikwalaho ka vana va Israyele entshaveni ya Sinayi.”' }
  ],
};